-- Generated by scripts/build-questions-seed.mjs
-- Idempotent: deletes existing rows before insert.
begin;
delete from practice_questions;
insert into practice_questions (external_key, subtest, topic_id, difficulty, stem, choices, correct_index, explanation, active) values
  ('GS-1', 'GS', 'gs.life-science', 2, 'Which organ is primarily responsible for filtering waste products from the blood and producing urine?', '["Liver","Kidney","Pancreas","Spleen"]'::jsonb, 1, 'The kidneys filter blood to remove waste products and excess water, which are excreted as urine. The liver processes nutrients and detoxifies chemicals but does not produce urine.', true),
  ('GS-2', 'GS', 'gs.physical-science', 2, 'Water (H₂O) is best classified as which of the following?', '["An element","A compound","A mixture","An isotope"]'::jsonb, 1, 'Water is a compound because it consists of two different elements — hydrogen and oxygen — chemically bonded in a fixed ratio. An element contains only one type of atom.', true),
  ('GS-3', 'GS', 'gs.earth-space-science', 2, 'Which layer of Earth''s atmosphere contains the ozone layer that absorbs most of the sun''s ultraviolet radiation?', '["Troposphere","Mesosphere","Stratosphere","Thermosphere"]'::jsonb, 2, 'The stratosphere, roughly 10–50 km above Earth''s surface, contains the ozone layer. The troposphere is the lowest layer where most weather occurs.', true),
  ('AR-1', 'AR', 'ar.rate-distance-time', 2, 'A car travels at 55 miles per hour. How many miles will it travel in 3 hours and 30 minutes?', '["165 miles","182.5 miles","192.5 miles","198 miles"]'::jsonb, 2, '3 hours 30 minutes = 3.5 hours. Distance = 55 × 3.5 = 192.5 miles.', true),
  ('AR-2', 'AR', 'ar.percent', 2, 'A store marks up an item by 40% from its wholesale cost of $35. What is the retail selling price?', '["$14.00","$45.50","$49.00","$52.50"]'::jsonb, 2, 'Markup = 40% × $35 = $14. Retail price = $35 + $14 = $49.00.', true),
  ('AR-3', 'AR', 'ar.ratio-proportion', 2, 'A recipe calls for flour and sugar in a ratio of 5:2. If you use 20 cups of flour, how many cups of sugar are needed?', '["4 cups","6 cups","8 cups","10 cups"]'::jsonb, 2, 'With a 5:2 ratio, sugar = (2/5) × 20 = 8 cups.', true),
  ('AR-4', 'AR', 'ar.percent', 2, 'A soldier earns $2,400 per month and saves 15% of that amount. After 6 months, how much has the soldier saved?', '["$1,440","$2,160","$2,400","$3,600"]'::jsonb, 1, 'Monthly savings = 15% × $2,400 = $360. Over 6 months: $360 × 6 = $2,160.', true),
  ('WK-1', 'WK', 'wk.synonyms', 1, 'ARID most nearly means:', '["Damp","Stormy","Dry","Fertile"]'::jsonb, 2, 'Arid means extremely dry, with little or no rain. It is commonly used to describe deserts or climates with very low precipitation.', true),
  ('WK-2', 'WK', 'wk.synonyms', 2, 'PRUDENT most nearly means:', '["Reckless","Cautious","Generous","Stubborn"]'::jsonb, 1, 'Prudent means acting with care and good judgment to avoid risk. It is the opposite of reckless.', true),
  ('WK-3', 'WK', 'wk.synonyms', 1, 'CONCISE most nearly means:', '["Wordy","Unclear","Brief","Detailed"]'::jsonb, 2, 'Concise means expressing information clearly in few words. It contrasts with wordy or verbose communication.', true),
  ('WK-4', 'WK', 'wk.synonyms', 2, 'OMINOUS most nearly means:', '["Cheerful","Threatening","Ordinary","Surprising"]'::jsonb, 1, 'Ominous means giving the impression that something bad or unpleasant is going to happen; it is synonymous with threatening or foreboding.', true),
  ('PC-1', 'PC', 'pc.main-idea', 2, 'Read the following passage and answer the question.

"Solar panels convert sunlight directly into electricity using photovoltaic cells. Unlike fossil fuels, solar energy produces no emissions during operation, making it one of the cleanest energy sources available."

What is the main idea of this passage?', '["Fossil fuels are harmful to the environment.","Solar panels require no maintenance.","Solar energy is a clean electricity source that uses photovoltaic cells.","Photovoltaic cells are expensive to manufacture."]'::jsonb, 2, 'The passage introduces how solar panels work and emphasizes that solar energy is clean and emission-free — that combination is the central point.', true),
  ('PC-2', 'PC', 'pc.inference', 2, 'Read the following passage and answer the question.

"The base commander issued new physical fitness standards requiring all personnel to complete a 2-mile run in under 18 minutes. Soldiers who fail to meet the standard will be enrolled in a remedial training program."

What can be inferred about soldiers who complete the run in exactly 18 minutes?', '["They will receive an award.","They will be enrolled in remedial training.","They have exceeded the standard.","They will be exempt from future tests."]'::jsonb, 1, 'The standard requires completing the run in under 18 minutes. Exactly 18 minutes does not meet the ''under 18'' requirement, so those soldiers would be enrolled in remedial training.', true),
  ('PC-3', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Dehydration impairs both physical and cognitive performance. Even a 2% loss of body water can reduce a person''s ability to concentrate and make decisions. Military personnel operating in hot climates must monitor fluid intake closely."

According to the passage, what effect does mild dehydration have?', '["It causes permanent cognitive damage.","It has no effect below 5% fluid loss.","It reduces the ability to concentrate and make decisions.","It only affects physical performance, not mental performance."]'::jsonb, 2, 'The passage explicitly states that a 2% loss of body water can reduce concentration and decision-making ability, affecting both physical and cognitive performance.', true),
  ('MK-1', 'MK', 'mk.geometry', 2, 'A rectangular room measures 14 feet long and 9 feet wide. What is the area of the room?', '["46 square feet","92 square feet","126 square feet","132 square feet"]'::jsonb, 2, 'Area of a rectangle = length × width = 14 × 9 = 126 square feet.', true),
  ('MK-2', 'MK', 'mk.algebra-linear', 1, 'Solve for x: 3x − 7 = 14', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 2, 'Add 7 to both sides: 3x = 21. Divide by 3: x = 7.', true),
  ('MK-3', 'MK', 'mk.exponents-polynomials', 1, 'What is the value of 2⁵?', '["10","16","25","32"]'::jsonb, 3, '2⁵ = 2 × 2 × 2 × 2 × 2 = 32.', true),
  ('MK-4', 'MK', 'mk.fractions-decimals', 2, 'What is ³⁄₄ divided by ³⁄₈?', '["½","1","2","9⁄32"]'::jsonb, 2, 'Dividing by a fraction means multiplying by its reciprocal: ³⁄₄ × ⁸⁄₃ = 24⁄12 = 2.', true),
  ('EI-1', 'EI', 'ei.ohms-law-power', 2, 'A circuit has a voltage of 12 volts and a resistance of 4 ohms. According to Ohm''s Law, what is the current flowing through the circuit?', '["0.33 amperes","3 amperes","8 amperes","48 amperes"]'::jsonb, 1, 'Ohm''s Law: I = V ÷ R = 12 ÷ 4 = 3 amperes.', true),
  ('EI-2', 'EI', 'ei.circuit-types', 2, 'In a series circuit with three light bulbs, one bulb burns out. What happens to the other two bulbs?', '["They burn brighter.","They continue operating normally.","They also go out.","They flicker but stay on."]'::jsonb, 2, 'In a series circuit, all components share a single path for current. If one bulb fails (opens the circuit), current cannot flow and all other bulbs go out.', true),
  ('EI-3', 'EI', 'ei.components-devices', 1, 'What unit is used to measure electrical resistance?', '["Volt","Ampere","Watt","Ohm"]'::jsonb, 3, 'Resistance is measured in ohms (Ω). Volts measure voltage, amperes measure current, and watts measure power.', true),
  ('AS-1', 'AS', 'as.hand-tools', 2, 'Which tool is best suited for tightening a bolt that is in a recessed or hard-to-reach location?', '["Open-end wrench","Socket wrench with extension","Adjustable pliers","Torque screwdriver"]'::jsonb, 1, 'A socket wrench with an extension bar allows a technician to reach fasteners in deep or confined spaces where an open-end wrench cannot fit.', true),
  ('AS-2', 'AS', 'as.vehicle-systems', 2, 'What is the primary function of a vehicle''s radiator?', '["Filter engine oil","Regulate fuel mixture","Dissipate heat from the engine coolant","Reduce exhaust emissions"]'::jsonb, 2, 'The radiator removes heat from the engine coolant by passing it through thin fins where air flow carries the heat away, preventing engine overheating.', true),
  ('AS-3', 'AS', 'as.shop-safety', 1, 'Before operating a power saw in a shop, you should FIRST:', '["Test the blade on scrap wood","Put on appropriate eye protection","Plug in the saw and let it warm up","Check the sharpness of the blade by touch"]'::jsonb, 1, 'Personal protective equipment — especially eye protection — must be donned before any shop operation begins. Blade fragments and sawdust present immediate eye hazards.', true),
  ('MC-1', 'MC', 'mc.levers-pulleys', 2, 'A 10-pound weight is placed 6 feet from the fulcrum of a lever. To balance it, how far from the fulcrum must a 15-pound weight be placed on the opposite side?', '["2 feet","4 feet","6 feet","9 feet"]'::jsonb, 1, 'Lever balance: W₁ × D₁ = W₂ × D₂ → 10 × 6 = 15 × D₂ → D₂ = 60 ÷ 15 = 4 feet.', true),
  ('MC-2', 'MC', 'mc.gears-wheels', 3, 'If a small gear with 10 teeth meshes with a large gear with 40 teeth, and the small gear rotates at 200 RPM, how fast does the large gear rotate?', '["25 RPM","50 RPM","100 RPM","800 RPM"]'::jsonb, 1, 'Gear ratio = 10/40 = 1/4. Large gear RPM = 200 × (10/40) = 200 × 0.25 = 50 RPM.', true),
  ('MC-3', 'MC', 'mc.forces-friction', 2, 'A 200-pound crate is resting on a flat surface. If you push it horizontally with a force of 50 pounds and it does not move, what is the force of friction acting on the crate?', '["0 pounds","50 pounds","150 pounds","200 pounds"]'::jsonb, 1, 'Since the crate is stationary (not accelerating), the net force is zero. Static friction exactly opposes the applied force, so friction = 50 pounds.', true),
  ('AO-1', 'AO', 'ao.3d-visualization', 3, 'A flat piece of material is cut into four identical right triangles, each with legs of equal length. If all four triangles are arranged so their right-angle corners meet at a center point, what shape do they form?', '["A circle","A rectangle","A square","A hexagon"]'::jsonb, 2, 'Four identical isosceles right triangles placed with their right angles at a common center and hypotenuses facing outward form a perfect square.', true),
  ('AO-2', 'AO', 'ao.paper-folding-nets', 1, 'A rectangular piece of paper is folded in half along its longest axis, then folded in half again along the same axis. When unfolded, how many equal sections does the paper have?', '["2","3","4","6"]'::jsonb, 2, 'Each fold doubles the number of sections. One fold → 2 sections; two folds → 4 equal sections.', true),
  ('AO-3', 'AO', 'ao.spatial-counting', 4, 'A cube is painted red on all six faces and then cut into 27 equal smaller cubes (a 3×3×3 grid). How many of the small cubes have paint on exactly two faces?', '["6","8","12","24"]'::jsonb, 2, 'Cubes with paint on exactly two faces sit along the edges (not corners) of the larger cube. A 3×3×3 cube has 12 edges, each contributing 1 such cube, giving 12 total.', true),
  ('GS-4', 'GS', 'gs.earth-space-science', 2, 'Which type of rock is formed when molten magma cools and solidifies?', '["Sedimentary","Metamorphic","Igneous","Organic"]'::jsonb, 2, 'Igneous rocks form from the cooling of molten rock (magma or lava). Sedimentary rocks form from compacted sediments, and metamorphic rocks form under heat and pressure.', true),
  ('GS-5', 'GS', 'gs.life-science', 2, 'Which of the following best describes the function of red blood cells?', '["Fight infection by producing antibodies","Transport oxygen throughout the body","Regulate blood clotting","Produce hormones"]'::jsonb, 1, 'Red blood cells (erythrocytes) contain hemoglobin, which binds to oxygen in the lungs and delivers it to tissues throughout the body.', true),
  ('GS-6', 'GS', 'gs.physics-mechanics', 2, 'Newton''s Third Law of Motion states that for every action there is:', '["An equal but delayed reaction","A greater and opposite reaction","An equal and opposite reaction","A proportional and parallel reaction"]'::jsonb, 2, 'Newton''s Third Law states that for every action force, there is an equal in magnitude and opposite in direction reaction force. This explains recoil, rocket propulsion, and walking.', true),
  ('AR-5', 'AR', 'ar.word-problems', 3, 'A tank holds 500 gallons of water. It drains at a rate of 25 gallons per minute and fills at 10 gallons per minute simultaneously. Starting with a full tank, how many minutes will it take to empty?', '["20 minutes","25 minutes","33 minutes","50 minutes"]'::jsonb, 2, 'Net drain rate = 25 − 10 = 15 gallons per minute. Time = 500 ÷ 15 ≈ 33.3, so approximately 33 minutes.', true),
  ('AR-6', 'AR', 'ar.arithmetic-fundamentals', 1, 'A platoon of 40 soldiers must carry 480 pounds of equipment equally. How many pounds does each soldier carry?', '["10 pounds","12 pounds","14 pounds","16 pounds"]'::jsonb, 1, '480 ÷ 40 = 12 pounds per soldier.', true),
  ('AR-7', 'AR', 'ar.percent', 2, 'A shirt originally priced at $60 is on sale for 25% off. What is the sale price?', '["$15","$40","$45","$50"]'::jsonb, 2, 'Discount = 25% × $60 = $15. Sale price = $60 − $15 = $45.', true),
  ('AR-8', 'AR', 'ar.word-problems', 4, 'Two workers can paint a room in 6 hours working together. If one worker can complete the job alone in 10 hours, how long would the second worker take alone?', '["12 hours","15 hours","16 hours","20 hours"]'::jsonb, 1, 'Combined rate = 1/6 room/hr. Worker 1 rate = 1/10. Worker 2 rate = 1/6 − 1/10 = 5/30 − 3/30 = 2/30 = 1/15. So Worker 2 takes 15 hours.', true),
  ('WK-5', 'WK', 'wk.synonyms', 2, 'TENACIOUS most nearly means:', '["Fragile","Persistent","Timid","Generous"]'::jsonb, 1, 'Tenacious means holding firmly to a purpose or position; persistent and determined. It implies stubbornness in a positive sense.', true),
  ('WK-6', 'WK', 'wk.synonyms', 2, 'AMBIGUOUS most nearly means:', '["Certain","Unclear","Ambitious","Honest"]'::jsonb, 1, 'Ambiguous means open to more than one interpretation; not having a clear meaning. It is distinct from ambitious, which relates to goals.', true),
  ('WK-7', 'WK', 'wk.synonyms', 1, 'VALIDATE most nearly means:', '["Deny","Confirm","Improve","Replace"]'::jsonb, 1, 'To validate means to confirm or check the accuracy or legitimacy of something. It is synonymous with verify or confirm.', true),
  ('WK-8', 'WK', 'wk.synonyms', 2, 'AUSTERE most nearly means:', '["Luxurious","Severe","Colorful","Warm"]'::jsonb, 1, 'Austere means severe or strict in manner or appearance; lacking comfort or ornament. It describes a plain, unadorned quality.', true),
  ('PC-4', 'PC', 'pc.inference', 2, 'Read the following passage and answer the question.

"The bald eagle was removed from the Endangered Species List in 2007, a success story for wildlife conservation. Once nearly extinct due to hunting and pesticide use, the population rebounded after DDT was banned in 1972 and legal protections were enacted."

What was the primary cause of the bald eagle''s recovery?', '["Captive breeding programs introduced thousands of new birds.","A ban on DDT and legal protections allowed the population to rebound.","Bald eagles adapted to living in urban environments.","Congress funded a national eagle relocation program."]'::jsonb, 1, 'The passage directly credits the banning of DDT and legal protections as the reasons for the population''s recovery.', true),
  ('PC-5', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Hypothermia occurs when the body loses heat faster than it can produce it, causing core body temperature to fall below 95°F. Symptoms progress from shivering and confusion to loss of coordination and, eventually, unconsciousness. Immediate warming and medical attention are critical."

According to the passage, which symptom appears first?', '["Unconsciousness","Loss of coordination","Shivering and confusion","Cardiac arrest"]'::jsonb, 2, 'The passage states that symptoms ''progress from shivering and confusion,'' meaning those are the earliest symptoms listed.', true),
  ('PC-6', 'PC', 'pc.detail-recall', 1, 'Read the following passage and answer the question.

"A convoy must maintain a 100-meter interval between vehicles at all times. Closing the gap increases the risk of collision if the lead vehicle stops suddenly. Drivers are responsible for maintaining their own interval regardless of road conditions."

Who is responsible for maintaining the correct vehicle interval?', '["The convoy commander","The lead vehicle driver","Each individual driver","The vehicle navigator"]'::jsonb, 2, 'The passage explicitly states that ''drivers are responsible for maintaining their own interval,'' making each individual driver responsible.', true),
  ('MK-5', 'MK', 'mk.geometry', 1, 'What is the perimeter of a square with a side length of 11 inches?', '["22 inches","33 inches","44 inches","121 inches"]'::jsonb, 2, 'Perimeter of a square = 4 × side = 4 × 11 = 44 inches.', true),
  ('MK-6', 'MK', 'mk.algebra-linear', 2, 'Solve for y: 5y + 3 = 2y + 18', '["y = 3","y = 5","y = 7","y = 9"]'::jsonb, 1, 'Subtract 2y from both sides: 3y + 3 = 18. Subtract 3: 3y = 15. Divide: y = 5.', true),
  ('MK-7', 'MK', 'mk.geometry', 2, 'A right triangle has legs measuring 6 cm and 8 cm. What is the length of the hypotenuse?', '["7 cm","10 cm","12 cm","14 cm"]'::jsonb, 1, 'By the Pythagorean theorem: c² = 6² + 8² = 36 + 64 = 100. c = √100 = 10 cm.', true),
  ('MK-8', 'MK', 'mk.fractions-decimals', 1, 'What is 15% of 240?', '["30","36","40","42"]'::jsonb, 1, '15% × 240 = 0.15 × 240 = 36.', true),
  ('EI-4', 'EI', 'ei.components-devices', 2, 'Which component in an electrical circuit allows current to flow in only one direction?', '["Resistor","Capacitor","Diode","Transformer"]'::jsonb, 2, 'A diode is a semiconductor device that permits current to flow in one direction only. It is commonly used to convert AC to DC in rectifier circuits.', true),
  ('EI-5', 'EI', 'ei.ohms-law-power', 2, 'A 60-watt light bulb operates on a 120-volt circuit. What is the current drawn by the bulb?', '["0.25 amperes","0.5 amperes","2 amperes","7,200 amperes"]'::jsonb, 1, 'Power (P) = Voltage (V) × Current (I). Solving for I: I = P ÷ V = 60 ÷ 120 = 0.5 amperes.', true),
  ('EI-6', 'EI', 'ei.components-devices', 2, 'What is the purpose of a fuse in an electrical circuit?', '["Increase voltage to components","Store electrical charge","Protect the circuit by breaking if current exceeds a safe level","Regulate alternating current frequency"]'::jsonb, 2, 'A fuse contains a thin metal element that melts and breaks the circuit if current exceeds its rated value, protecting wiring and components from damage.', true),
  ('AS-4', 'AS', 'as.vehicle-systems', 2, 'What does a vehicle''s alternator do while the engine is running?', '["Starts the engine by cranking it","Recharges the battery and powers electrical systems","Controls fuel injection timing","Regulates engine coolant temperature"]'::jsonb, 1, 'The alternator converts mechanical energy from the engine into electrical energy, recharging the battery and supplying power to the vehicle''s electrical systems while the engine runs.', true),
  ('AS-5', 'AS', 'as.hand-tools', 1, 'Which type of screwdriver is designed to fit a screw head with an X-shaped slot?', '["Flathead screwdriver","Torx screwdriver","Phillips screwdriver","Hex screwdriver"]'::jsonb, 2, 'A Phillips screwdriver has a cross-shaped tip designed to fit X-shaped (Phillips) screw head recesses, providing better torque than a flathead.', true),
  ('AS-6', 'AS', 'as.maintenance-repair', 2, 'When should a vehicle''s engine oil be replaced most regularly, according to general maintenance practice?', '["Only when the oil pressure warning light activates","At every fuel fill-up","At intervals recommended by the manufacturer, typically based on mileage or time","Once per year regardless of mileage"]'::jsonb, 2, 'Manufacturers specify oil change intervals (commonly every 3,000–7,500 miles or more with synthetic oil) based on engineering data. Following these intervals prevents engine wear.', true),
  ('MC-4', 'MC', 'mc.gears-wheels', 2, 'A wheel and axle system has a wheel with a radius of 12 inches and an axle with a radius of 3 inches. What is the mechanical advantage of this system?', '["2","3","4","6"]'::jsonb, 2, 'Mechanical advantage of a wheel and axle = wheel radius ÷ axle radius = 12 ÷ 3 = 4.', true),
  ('MC-5', 'MC', 'mc.levers-pulleys', 2, 'A fixed pulley changes the direction of force but does NOT change the amount of force required. Which statement about a fixed pulley is correct?', '["It reduces the force needed by half.","It multiplies the force by the number of rope segments.","It redirects the force without any mechanical advantage.","It eliminates the effect of gravity on the load."]'::jsonb, 2, 'A single fixed pulley only redirects the pulling force; it does not reduce the effort required to lift the load. Mechanical advantage = 1.', true),
  ('MC-6', 'MC', 'mc.forces-friction', 2, 'Which of the following changes would increase the pressure exerted by a block resting on a table?', '["Tilting the block at a 45-degree angle","Increasing the surface area in contact with the table","Placing the block on a smaller face so less area contacts the table","Moving the block to the center of the table"]'::jsonb, 2, 'Pressure = Force ÷ Area. Reducing the contact area while keeping the weight the same increases the pressure, since the same force is concentrated on a smaller surface.', true),
  ('AO-4', 'AO', 'ao.paper-folding-nets', 2, 'A square piece of cardboard has a small square cut from each of its four corners. When the sides are folded up along the cut lines, what shape is formed?', '["A pyramid","An open-top box","A cylinder","A cone"]'::jsonb, 1, 'Cutting squares from each corner and folding up the resulting flaps creates an open-top rectangular box — a standard net-folding construction.', true),
  ('AO-5', 'AO', 'ao.3d-visualization', 2, 'A solid cylinder is sliced straight down through its center from top to bottom (a vertical cut through the axis). What shape is the cross-section?', '["Circle","Ellipse","Rectangle","Triangle"]'::jsonb, 2, 'Cutting a cylinder along its axis (lengthwise through the center) produces a rectangular cross-section whose width equals the cylinder''s diameter and height equals its length.', true),
  ('AO-6', 'AO', 'ao.spatial-counting', 3, 'Three identical equilateral triangles are placed so that one vertex of each meets at a common center point and the triangles do not overlap. What is the total interior angle at the center point?', '["180 degrees","240 degrees","270 degrees","360 degrees"]'::jsonb, 0, 'Three equilateral triangles meeting at a vertex contribute their three 60° interior corners. Total angle contribution = 3 × 60° = 180°. The ‘angles around a point sum to 360°’ rule applies only when shapes tile the entire space around the point — here they don’t, since 180° leaves 180° of the surrounding plane uncovered.', true),
  ('GS-7', 'GS', 'gs.life-science', 2, 'Photosynthesis in plants primarily uses which two resources to produce glucose?', '["Oxygen and nitrogen","Carbon dioxide and water","Glucose and oxygen","Nitrogen and phosphorus"]'::jsonb, 1, 'Plants use carbon dioxide (CO₂) from the air and water (H₂O) from the soil, along with sunlight energy, to produce glucose through photosynthesis.', true),
  ('GS-8', 'GS', 'gs.earth-space-science', 1, 'Which planet in our solar system is largest by diameter?', '["Saturn","Neptune","Jupiter","Uranus"]'::jsonb, 2, 'Jupiter is the largest planet in the solar system, with a diameter of about 143,000 km — more than 11 times the diameter of Earth.', true),
  ('GS-9', 'GS', 'gs.physical-science', 2, 'In an acid-base reaction, the pH of a neutral solution is:', '["0","7","10","14"]'::jsonb, 1, 'The pH scale runs from 0 (most acidic) to 14 (most basic/alkaline). A pH of 7 represents a neutral solution, such as pure water.', true),
  ('AR-9', 'AR', 'ar.ratio-proportion', 2, 'If 5 pens cost $3.75, what is the cost of 8 pens at the same price?', '["$5.00","$5.60","$6.00","$6.25"]'::jsonb, 2, 'Price per pen = $3.75 ÷ 5 = $0.75. Cost of 8 pens = 8 × $0.75 = $6.00.', true),
  ('AR-10', 'AR', 'ar.arithmetic-fundamentals', 2, 'A rectangular field is 120 yards long and 80 yards wide. What is its area in square yards?', '["4,800","8,400","9,600","10,400"]'::jsonb, 2, 'Area = length × width = 120 × 80 = 9,600 square yards.', true),
  ('AR-11', 'AR', 'ar.rate-distance-time', 3, 'A train leaves a station at 9:00 AM traveling at 60 mph. A second train leaves the same station at 10:00 AM traveling in the same direction at 90 mph. At what time does the second train catch up to the first?', '["11:00 AM","12:00 PM","12:30 PM","1:00 PM"]'::jsonb, 1, 'After 1 hour, Train 1 is 60 miles ahead. Closing rate = 90 − 60 = 30 mph. Time to close gap = 60 ÷ 30 = 2 hours after 10:00 AM = 12:00 PM.', true),
  ('AR-12', 'AR', 'ar.ratio-proportion', 2, 'A map has a scale of 1 inch = 50 miles. Two cities are 3.5 inches apart on the map. What is the actual distance between them?', '["150 miles","175 miles","200 miles","225 miles"]'::jsonb, 1, 'Actual distance = 3.5 × 50 = 175 miles.', true),
  ('WK-9', 'WK', 'wk.synonyms', 2, 'DILIGENT most nearly means:', '["Lazy","Careful","Hardworking","Honest"]'::jsonb, 2, 'Diligent means showing steady, earnest effort in one''s work or duties. It is closest in meaning to hardworking or industrious.', true),
  ('WK-10', 'WK', 'wk.synonyms', 2, 'VOLATILE most nearly means:', '["Stable","Unstable","Heavy","Silent"]'::jsonb, 1, 'Volatile describes something that is liable to change rapidly and unpredictably, especially for the worse. It suggests instability or explosiveness.', true),
  ('WK-11', 'WK', 'wk.synonyms', 2, 'EXPEDITE most nearly means:', '["Delay","Organize","Accelerate","Evaluate"]'::jsonb, 2, 'To expedite means to speed up the process of something; to cause it to happen more quickly. It is synonymous with accelerate or hasten.', true),
  ('WK-12', 'WK', 'wk.synonyms', 2, 'METICULOUS most nearly means:', '["Careless","Precise","Modest","Flexible"]'::jsonb, 1, 'Meticulous means showing great attention to detail; very careful and precise. It describes someone who is thorough and exact.', true),
  ('PC-7', 'PC', 'pc.inference', 3, 'Read the following passage and answer the question.

"Antibiotics are effective against bacterial infections but have no effect on viral illnesses such as the common cold or influenza. Overuse of antibiotics has led to the emergence of drug-resistant bacteria, which pose a significant public health threat."

What conclusion can be drawn from this passage?', '["Antibiotics should be prescribed for all infections to prevent complications.","Viral and bacterial infections require the same treatment.","Using antibiotics unnecessarily contributes to antibiotic resistance.","The common cold can be cured with the right antibiotic."]'::jsonb, 2, 'The passage states that overuse of antibiotics leads to drug-resistant bacteria, implying that using them when unnecessary worsens the resistance problem.', true),
  ('PC-8', 'PC', 'pc.detail-recall', 2, 'Read the following passage and answer the question.

"Night vision devices amplify existing light, such as moonlight or starlight, to allow soldiers to see in low-light environments. Unlike infrared thermal devices, which detect heat signatures, night vision devices cannot function in complete darkness."

What is one limitation of night vision devices mentioned in the passage?', '["They are too heavy for field use.","They detect heat signatures rather than light.","They cannot function in complete darkness.","They can only be used by specially trained soldiers."]'::jsonb, 2, 'The passage explicitly states that night vision devices cannot function in complete darkness because they amplify existing light and require some ambient light to work.', true),
  ('PC-9', 'PC', 'pc.main-idea', 2, 'Read the following passage and answer the question.

"The Army''s supply chain relies on a system known as LOGCAP (Logistics Civil Augmentation Program), which contracts civilian companies to provide support services in combat zones. This allows military units to focus on combat operations rather than logistics management."

What is the main purpose of LOGCAP according to the passage?', '["To replace all military logistics units with civilian workers","To allow military units to concentrate on combat by outsourcing support services","To reduce the overall size of the military budget","To train civilian contractors in military combat tactics"]'::jsonb, 1, 'The passage states that LOGCAP contracts civilian companies for support services specifically so that military units can focus on combat operations.', true),
  ('MK-9', 'MK', 'mk.exponents-polynomials', 2, 'Simplify: (3x²)(4x³)', '["7x⁵","12x⁵","12x⁶","7x⁶"]'::jsonb, 1, 'Multiply coefficients: 3 × 4 = 12. Add exponents: x² × x³ = x⁵. Result: 12x⁵.', true),
  ('MK-10', 'MK', 'mk.geometry', 2, 'What is the circumference of a circle with a diameter of 10 inches? (Use π ≈ 3.14)', '["15.7 inches","31.4 inches","78.5 inches","314 inches"]'::jsonb, 1, 'Circumference = π × diameter = 3.14 × 10 = 31.4 inches.', true),
  ('MK-11', 'MK', 'mk.fractions-decimals', 2, 'If the ratio of boys to girls in a class is 3:5 and there are 24 boys, how many girls are in the class?', '["32","36","40","48"]'::jsonb, 2, 'Girls = (5/3) × 24 = 40.', true),
  ('MK-12', 'MK', 'mk.number-properties', 1, 'Evaluate: |−18| + |5|', '["−13","13","23","−23"]'::jsonb, 2, 'Absolute value removes the sign: |−18| = 18, |5| = 5. Sum = 18 + 5 = 23.', true),
  ('EI-7', 'EI', 'ei.circuit-types', 3, 'Two resistors of 6 ohms each are connected in parallel. What is the total resistance of the combination?', '["12 ohms","6 ohms","3 ohms","1 ohm"]'::jsonb, 2, 'For two equal resistors (R) in parallel, total resistance = R ÷ 2 = 6 ÷ 2 = 3 ohms. Formula: 1/Rt = 1/6 + 1/6 = 2/6, so Rt = 3 ohms.', true),
  ('EI-8', 'EI', 'ei.conductors-insulators', 1, 'Which material is the BEST electrical conductor?', '["Rubber","Glass","Copper","Wood"]'::jsonb, 2, 'Copper is one of the best electrical conductors available and is widely used in wiring. Rubber, glass, and wood are insulators that resist current flow.', true),
  ('EI-9', 'EI', 'ei.components-devices', 3, 'A transformer has 100 turns on its primary coil and 400 turns on its secondary coil. If the primary voltage is 120 volts, what is the secondary voltage?', '["30 volts","120 volts","480 volts","600 volts"]'::jsonb, 2, 'Transformer ratio: Vs/Vp = Ns/Np → Vs = 120 × (400/100) = 120 × 4 = 480 volts.', true),
  ('AS-7', 'AS', 'as.vehicle-systems', 3, 'What is the purpose of a vehicle''s timing belt or timing chain?', '["Transfer power from the transmission to the wheels","Synchronize the rotation of the crankshaft and camshaft","Connect the steering column to the front wheels","Regulate fuel pressure in the injection system"]'::jsonb, 1, 'The timing belt/chain synchronizes the crankshaft and camshaft so that engine valves open and close at the correct times during each piston stroke.', true),
  ('AS-8', 'AS', 'as.hand-tools', 3, 'Which hand tool would you use to measure the outside diameter of a cylindrical metal rod precisely?', '["Tape measure","Inside caliper","Outside micrometer","Combination square"]'::jsonb, 2, 'An outside micrometer provides precise measurements of the outer dimensions of cylindrical objects, with accuracy to thousandths of an inch.', true),
  ('AS-9', 'AS', 'as.shop-safety', 3, 'When welding, the primary purpose of a ground clamp attached to the workpiece is to:', '["Prevent the metal from warping","Complete the electrical circuit for the welding arc","Cool the metal after welding","Indicate the direction of welding travel"]'::jsonb, 1, 'The ground clamp completes the electrical circuit from the welder through the workpiece, allowing current to flow and create the arc needed for welding.', true),
  ('MC-7', 'MC', 'mc.forces-friction', 2, 'If a hydraulic jack applies 10 pounds of force over a piston with an area of 2 square inches, what is the pressure transmitted through the hydraulic fluid?', '["2 psi","5 psi","12 psi","20 psi"]'::jsonb, 1, 'Pressure = Force ÷ Area = 10 ÷ 2 = 5 pounds per square inch (psi). This pressure is transmitted equally throughout the fluid.', true),
  ('MC-8', 'MC', 'mc.motion-projectile', 2, 'A ball rolls off a horizontal table and follows a curved path to the ground. This curved path is an example of which type of motion?', '["Circular motion","Simple harmonic motion","Projectile motion","Linear motion"]'::jsonb, 2, 'When an object has a horizontal velocity and is acted on by gravity, it follows a curved (parabolic) path called projectile motion — a combination of horizontal and vertical components.', true),
  ('MC-9', 'MC', 'mc.inclined-plane-hydraulics', 3, 'In an inclined plane, increasing the length of the ramp while keeping the height constant will:', '["Increase the effort force needed to move the load","Decrease the mechanical advantage","Increase the mechanical advantage by reducing effort force","Have no effect on mechanical advantage"]'::jsonb, 2, 'Mechanical advantage of an inclined plane = ramp length ÷ height. A longer ramp with the same height produces a larger mechanical advantage, reducing the effort force required.', true),
  ('AO-7', 'AO', 'ao.3d-visualization', 1, 'A standard six-sided die is held so that the 1 faces up. Which number is on the face directly opposite the 1?', '["2","4","6","5"]'::jsonb, 2, 'On a standard die, opposite faces always sum to 7. The face opposite the 1 is 6 (1 + 6 = 7).', true),
  ('AO-9', 'AO', 'ao.spatial-counting', 2, 'A 12-inch ruler is broken into two pieces. One piece is twice as long as the other. What are the lengths of the two pieces?', '["3 inches and 9 inches","4 inches and 8 inches","5 inches and 7 inches","6 inches and 6 inches"]'::jsonb, 1, 'Let the shorter piece = x. Then 2x = longer piece. x + 2x = 12 → 3x = 12 → x = 4. The pieces are 4 inches and 8 inches.', true),
  ('WK-CTX-1', 'WK', 'wk.context-clues', 3, 'In the sentence ''The senator''s VERBOSE reply frustrated reporters who needed a simple yes or no,'' the word VERBOSE most nearly means:', '["enthusiastic","evasive","using more words than necessary","difficult to hear"]'::jsonb, 2, 'Verbose means using an unnecessarily large number of words. The clue ''needed a simple yes or no'' signals that the reply was overly wordy, not merely evasive or hard to hear.', true),
  ('WK-CTX-2', 'WK', 'wk.context-clues', 3, 'In the sentence ''After three sleepless days on patrol, the soldiers were so TORPID they could barely lift their rifles,'' the word TORPID most nearly means:', '["alert","sluggish","angry","well-trained"]'::jsonb, 1, 'Torpid means sluggish or mentally/physically inactive. The context clue ''sleepless days'' and ''could barely lift their rifles'' points directly to extreme sluggishness, not anger or alertness.', true),
  ('WK-CTX-3', 'WK', 'wk.context-clues', 3, 'In the sentence ''The mechanic''s METICULOUS inspection found three hairline cracks that a quick look would have missed,'' the word METICULOUS most nearly means:', '["rushed","extremely careful","expensive","routine"]'::jsonb, 1, 'Meticulous means paying very careful attention to detail. The clue that the inspection found defects ''a quick look would have missed'' confirms thoroughness, not speed or routine procedure.', true),
  ('WK-CTX-4', 'WK', 'wk.context-clues', 4, 'In the sentence ''The commander''s TACITURN nature meant that junior soldiers rarely received direct feedback, leaving them to interpret his single nods as either praise or disapproval,'' the word TACITURN most nearly means:', '["stern and demanding","reluctant to speak","unpredictable in mood","fair but strict"]'::jsonb, 1, 'Taciturn means habitually saying very little. The sentence''s clue is that soldiers got no verbal feedback at all, only nods — indicating a person who rarely speaks, not one who is merely stern or moody.', true),
  ('WK-CTX-5', 'WK', 'wk.context-clues', 3, 'In the sentence ''The hiking trail was so ARDUOUS that even the most experienced climbers needed rest breaks every half mile,'' the word ARDUOUS most nearly means:', '["scenic","demanding","well-marked","narrow"]'::jsonb, 1, 'Arduous means requiring great effort and endurance. ''Even the most experienced climbers needed rest breaks'' signals extreme difficulty, not just narrowness or poor signage.', true),
  ('WK-CTX-6', 'WK', 'wk.context-clues', 4, 'In the sentence ''Her SARDONIC smile told the interviewer she found the question absurd, though she answered politely,'' the word SARDONIC most nearly means:', '["warm and welcoming","mocking or grimly humorous","nervous and tense","bright and enthusiastic"]'::jsonb, 1, 'Sardonic means grimly mocking or cynically humorous. The clue ''found the question absurd'' while still being outwardly polite is characteristic of sardonic expression. Warm or enthusiastic contradicts the implied disdain.', true),
  ('WK-CTX-7', 'WK', 'wk.context-clues', 3, 'In the sentence ''Because the new regulation was so AMBIGUOUS, different base commanders interpreted it in completely different ways,'' the word AMBIGUOUS most nearly means:', '["strict","open to more than one interpretation","widely publicized","recently updated"]'::jsonb, 1, 'Ambiguous means open to multiple interpretations. The evidence is that commanders read it differently — something strict or widely publicized would produce uniform results, not varied ones.', true),
  ('WK-CTX-8', 'WK', 'wk.context-clues', 3, 'In the sentence ''Despite losing power for three days, the team remained RESILIENT and rebuilt the network faster than expected,'' the word RESILIENT most nearly means:', '["resourceful","quick to recover from setbacks","highly trained","well-funded"]'::jsonb, 1, 'Resilient means able to recover quickly from difficulties. ''Despite losing power'' sets up the adversity, and ''rebuilt faster than expected'' confirms swift recovery — the core meaning of resilience.', true),
  ('WK-CTX-9', 'WK', 'wk.context-clues', 4, 'In the sentence ''The general''s IMPERIOUS tone left no doubt that his orders were not suggestions — they were commands,'' the word IMPERIOUS most nearly means:', '["calm and measured","domineering and commanding","persuasive and logical","vague and uncertain"]'::jsonb, 1, 'Imperious means arrogantly domineering. The contrast between ''not suggestions'' and ''commands'' reinforces a tone that expects immediate obedience. Persuasive implies reasoning and choice, which contradicts the passage''s meaning.', true),
  ('WK-CTX-10', 'WK', 'wk.context-clues', 3, 'In the sentence ''The scientist''s HYPOTHESIS, though TENUOUS at first, grew stronger as more experimental data came in,'' the word TENUOUS most nearly means:', '["widely accepted","poorly worded","weak or lacking support","based on observation"]'::jsonb, 2, 'Tenuous means thin or weak, often used to describe an argument or idea with little supporting evidence. The phrase ''grew stronger as more data came in'' confirms it started from a position of minimal support.', true),
  ('WK-CTX-11', 'WK', 'wk.context-clues', 4, 'In the sentence ''The judge''s IMPARTIAL ruling satisfied both sides because neither could claim favoritism,'' the word IMPARTIAL most nearly means:', '["biased toward the defendant","based on strict law","treating all sides equally without favoritism","delivered quickly"]'::jsonb, 2, 'Impartial means not favoring one side over another. ''Neither could claim favoritism'' is the direct context clue. ''Based on strict law'' is tempting but describes method rather than the fairness quality the word captures.', true),
  ('WK-CTX-12', 'WK', 'wk.context-clues', 5, 'In the sentence ''His PERFUNCTORY review of the safety checklist — glancing at it for seconds before signing — nearly cost the crew their lives,'' the word PERFUNCTORY most nearly means:', '["thorough and systematic","done as a formality without real care","delayed and overdue","conducted by a supervisor"]'::jsonb, 1, 'Perfunctory means carried out with minimal effort and as a routine duty, not with genuine care. ''Glancing at it for seconds before signing'' is the exact clue; the near-catastrophe underscores how inadequate it was.', true),
  ('WK-PFX-1', 'WK', 'wk.prefixes-suffixes', 3, 'The word ANTECEDENT contains the prefix ANTE-. Based on that prefix, ANTECEDENT most nearly means:', '["something that comes after","something that came before","something that contradicts","something that repeats"]'::jsonb, 1, 'ANTE- means before or preceding (compare: antebellum, anteroom). An antecedent is a thing or event that came before another. ANTI- (against) is the common confusion, but the spelling here is ANTE-.', true),
  ('WK-PFX-2', 'WK', 'wk.prefixes-suffixes', 3, 'The word BENEVOLENT contains the root VOL (wish, will) and the prefix BENE-. BENEVOLENT most nearly means:', '["well-wishing or kind","all-powerful","voluntary","truthful"]'::jsonb, 0, 'BENE- means well or good (benefit, benefactor). Combined with -VOL- (wish), benevolent means well-wishing or kindly disposed. Voluntary shares the same root but a different prefix.', true),
  ('WK-PFX-3', 'WK', 'wk.prefixes-suffixes', 3, 'The suffix -LOGY means the study of. CHRONOLOGY is therefore best defined as:', '["the science of timekeeping devices","the arrangement of events in time order","a record of weather patterns","the study of ancient languages"]'::jsonb, 1, 'CHRONO- means time; -LOGY means study or systematic knowledge. Chronology is the arrangement and study of events in time sequence. A chronograph measures time but -GRAPH means write or record, not study.', true),
  ('WK-PFX-4', 'WK', 'wk.prefixes-suffixes', 4, 'The word CIRCUMSPECT contains the prefix CIRCUM- (around) and the root SPECT (look). CIRCUMSPECT most nearly means:', '["easily distracted","wary and considering all possibilities","surrounded by obstacles","quick to decide"]'::jsonb, 1, 'Circumspect literally means ''looking around'' — considering all circumstances before acting, hence wary and careful. Quick to decide is the opposite. ''Surrounded by obstacles'' misreads CIRCUM- as a physical description.', true),
  ('WK-PFX-5', 'WK', 'wk.prefixes-suffixes', 3, 'The prefix TRANS- means across or through. A TRANSOCEANIC voyage is therefore a voyage:', '["below the ocean surface","along the coastline","across an ocean","within a single ocean region"]'::jsonb, 2, 'TRANS- means across or through, as in transport, transfer, transatlantic. Transoceanic means crossing an ocean from one side to the other.', true),
  ('WK-PFX-6', 'WK', 'wk.prefixes-suffixes', 4, 'The word EQUIVOCAL contains the prefix EQUI- (equal) and the root VOC (voice/call). EQUIVOCAL most nearly means:', '["equally loud","open to two interpretations","fair and balanced","clearly stated"]'::jsonb, 1, 'Equivocal literally means ''equal voices'' — a statement that calls equally in two directions, making it deliberately ambiguous or unclear. Clearly stated is the antonym. Fair and balanced is a trap that uses EQUI- in isolation.', true),
  ('WK-PFX-7', 'WK', 'wk.prefixes-suffixes', 4, 'The suffix -OLOGY means the study of, while -OLOGIST means one who studies. A SEISMOLOGIST studies:', '["the structure of the atmosphere","earthquake activity","ocean currents","ancient fossils"]'::jsonb, 1, 'SEISMO- derives from the Greek seismos, meaning earthquake or shaking. A seismologist studies earthquakes and seismic waves. Fossils (paleontology) and ocean currents (oceanography) involve different prefixes.', true),
  ('WK-PFX-8', 'WK', 'wk.prefixes-suffixes', 5, 'The word MAGNANIMOUS contains the roots MAGN- (great) and ANIM- (spirit/soul). MAGNANIMOUS most nearly means:', '["physically large and imposing","generous in forgiving insults or injuries","highly educated","emotionally volatile"]'::jsonb, 1, 'Magnanimous means ''great-spirited'' — generous, noble, and especially forgiving toward rivals or those who have wronged you. Physically large (magnitude) uses the same root but the ANIM- component shifts meaning toward character, not size.', true),
  ('WK-ROOT-1', 'WK', 'wk.root-words', 3, 'The word AUDIBLE shares its root with AUDITORIUM and AUDIENCE. The root AUD- means:', '["to speak","to hear","to see","to gather"]'::jsonb, 1, 'AUD- comes from the Latin audire, to hear. Audible means capable of being heard; an auditorium is a place for hearing performances; an audience is a group of listeners.', true),
  ('WK-ROOT-2', 'WK', 'wk.root-words', 3, 'The root CHRON appears in CHRONIC, CHRONOMETER, and ANACHRONISM. CHRON means:', '["color","time","order","distance"]'::jsonb, 1, 'CHRON comes from the Greek chronos, meaning time. A chronometer measures time precisely; an anachronism is something placed in the wrong time period; chronic means persisting over a long time.', true),
  ('WK-ROOT-3', 'WK', 'wk.root-words', 3, 'The root TERRA appears in TERRITORY, TERRAIN, and MEDITERRANEAN. TERRA most nearly means:', '["water","sky","earth or land","boundary"]'::jsonb, 2, 'TERRA comes from Latin meaning earth or land. Mediterranean literally means ''middle of the earth (land)''; terrain refers to the features of a stretch of land; territory is a defined area of land.', true),
  ('WK-ROOT-4', 'WK', 'wk.root-words', 4, 'The root SCRIB/SCRIPT appears in PRESCRIBE, DESCRIBE, INSCRIPTION, and MANUSCRIPT. This root most nearly means:', '["to speak","to write","to order","to carve"]'::jsonb, 1, 'SCRIB/SCRIPT comes from the Latin scribere, to write. Manuscript means handwritten; inscription is writing carved into a surface; prescribe originally meant to write before (instructions). ''To carve'' is a trap because inscriptions are carved, but the root itself means write.', true),
  ('WK-ROOT-5', 'WK', 'wk.root-words', 4, 'The root RUPT appears in INTERRUPT, DISRUPT, ERUPT, and RUPTURE. RUPT most nearly means:', '["to flow","to break or burst","to begin","to connect"]'::jsonb, 1, 'RUPT comes from the Latin rumpere, to break. Interrupt means to break into; disrupt means to break apart; erupt means to burst out; rupture is a break or tear. ''To flow'' is a trap because eruptions involve flow, but the root captures the breaking action.', true),
  ('WK-ROOT-6', 'WK', 'wk.root-words', 5, 'The root LOQUI/LOCUT appears in ELOQUENT, COLLOQUIAL, LOQUACIOUS, and SOLILOQUY. This root most nearly means:', '["to listen","to write formally","to speak","to persuade"]'::jsonb, 2, 'LOQUI/LOCUT comes from the Latin loqui, to speak. Eloquent means speaking with fluency and force; loquacious means very talkative; colloquial refers to everyday spoken language; a soliloquy is speaking alone. ''To persuade'' is tempting for eloquent, but persuasion is an effect, not the root''s meaning.', true),
  ('PC-ATP-1', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"Every year, thousands of young people sign contracts they do not fully understand, binding themselves to financial obligations that can follow them for a decade. Financial literacy is not a luxury — it is a survival skill. Schools that skip personal finance education are not saving curriculum space; they are failing their students."

The author''s primary purpose is to:', '["explain how financial contracts work","argue that financial education should be required in schools","describe the difficulties young people face after graduation","compare different methods of teaching personal finance"]'::jsonb, 1, 'The passage makes a direct argument: schools that skip financial literacy are ''failing their students.'' The word ''failing'' signals advocacy, not neutral description. The author is not explaining contract mechanics or comparing teaching methods.', true),
  ('PC-ATP-2', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"The old lighthouse stood at the edge of the cliff, its white paint peeling, its lamp long dark. Fishermen who once depended on its beam now navigated by GPS coordinates that glowed on small screens below the wheelhouse. Progress, it seemed, had made the lighthouse beautiful again — no longer a tool, just a memory."

The author''s tone toward the lighthouse can best be described as:', '["angry at the march of technology","nostalgic and somewhat wistful","proud of modern navigation advances","indifferent to the lighthouse''s fate"]'::jsonb, 1, '''Beautiful again — no longer a tool, just a memory'' expresses a wistful, nostalgic view of something that has outlived its usefulness. The author is not angry — progress is accepted — but there is a gentle sense of loss, not pride or indifference.', true),
  ('PC-ATP-3', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"The study followed 400 adults over 20 years and found that those who slept fewer than six hours per night had a 35 percent higher incidence of cardiovascular events than those who slept seven to eight hours. Researchers controlled for diet, exercise, and body mass index. The correlation was consistent across age groups and geographic regions."

The author''s tone is best described as:', '["alarmed and warning readers to change habits","objective and informative","persuasive, urging policy reform","skeptical of the study''s methodology"]'::jsonb, 1, 'The passage reports data and controlled variables without emotional language or calls to action. ''Controlled for diet, exercise, and BMI'' signals scientific rigor, not alarm or advocacy. Skeptical would involve questioning the methods, which the author does not do.', true),
  ('PC-ATP-4', 'PC', 'pc.author-tone-purpose', 3, 'Read the passage below and answer the question.

"If you have ever watched a skilled carpenter fit two pieces of wood together without a visible gap, you have witnessed craftsmanship at its best. It is not magic — it is patience, the right tools, and a refusal to accept ''good enough.'' Anyone who calls woodworking a dying art has never stood in a shop full of sawdust and purpose."

The author''s attitude toward woodworking is best described as:', '["defensive and insecure about the craft''s future","enthusiastic and admiring","neutral and informational","critical of beginners who rush their work"]'::jsonb, 1, '''Craftsmanship at its best,'' ''patience,'' and ''sawdust and purpose'' all express genuine admiration. The author does mention critics but counters them confidently rather than defensively, and offers no criticism of beginners specifically.', true),
  ('PC-ATP-5', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"The proposal to expand the highway through the wetland was approved in 72 hours — a process that typically takes months of environmental review. Local conservation groups were not notified until after the vote. Three federal agencies later noted that proper procedure had not been followed, yet construction began on schedule."

The author''s implied attitude toward the approval process is:', '["supportive of faster infrastructure decisions","critical of the rushed and irregular process","neutral, simply reporting a timeline","uncertain about whether the wetland matters"]'::jsonb, 1, 'The author selects details that expose procedural shortcuts: a 72-hour decision on a months-long process, no public notification, federal agencies noting violations. This pattern of detail selection signals criticism even without explicit judgment words.', true),
  ('PC-ATP-6', 'PC', 'pc.author-tone-purpose', 4, 'Read the passage below and answer the question.

"Wolves were reintroduced to Yellowstone in 1995. Within a decade, the elk population shifted its grazing patterns away from riverbanks, allowing willows and aspens to regrow. Beavers returned; their dams slowed erosion; streambeds narrowed and deepened. A single predator had changed the rivers."

The author''s primary purpose is to:', '["argue that wolf populations should be expanded throughout the country","illustrate how the reintroduction of one species can reshape an entire ecosystem","criticize the original removal of wolves from Yellowstone","describe the daily behavior of wolves in the wild"]'::jsonb, 1, 'The passage traces a chain of ecological effects from one decision, building to ''a single predator had changed the rivers.'' This is an illustrative, cause-and-effect purpose. The author does not call for expanded wolf populations or criticize past decisions.', true),
  ('PC-ATP-7', 'PC', 'pc.author-tone-purpose', 5, 'Read the passage below and answer the question.

"Efficiency, we are often told, is the highest virtue of a modern organization. But efficiency is a tool, not a goal. A surgeon who operates faster does not thereby become a better surgeon; a teacher who covers content faster is not necessarily teaching. When organizations optimize processes without asking what those processes are for, they risk becoming very good at doing the wrong thing."

The author''s attitude toward efficiency is best described as:', '["strongly opposed to using efficiency in any professional context","cautiously skeptical — useful in the right place, but easily misapplied","fully supportive if efficiency is paired with speed","indifferent; the author is presenting both sides without a position"]'::jsonb, 1, 'The author calls efficiency ''a tool, not a goal'' and uses examples to show how misapplied efficiency backfires — but never argues against efficiency itself. This is cautious skepticism, not wholesale opposition. The author clearly has a position, ruling out indifference.', true),
  ('PC-ATP-8', 'PC', 'pc.author-tone-purpose', 5, 'Read the passage below and answer the question.

"The recruits arrived in October — cocky, loud, certain they were ready for anything. By December, most had stopped talking about what they thought training would be like. They had learned something that cannot be taught in a classroom: that confidence earned is different from confidence assumed."

The author''s tone toward the recruits at the end of the passage is best described as:', '["contemptuous of their early arrogance","approving of the growth they experienced","pessimistic about their long-term prospects","amused by their naivety throughout"]'::jsonb, 1, '''Confidence earned is different from confidence assumed'' is the author''s conclusion — framing the change as meaningful growth, not humiliation. Contemptuous would suggest the author mocks them; the passage instead presents the transformation with respect.', true),
  ('AS-MNT-1', 'AS', 'as.maintenance-repair', 3, 'Engine oil should be changed at regular intervals primarily to:', '["increase fuel octane rating","remove contaminants and restore lubricating properties","cool the transmission fluid","maintain proper tire pressure"]'::jsonb, 1, 'Over time, engine oil accumulates metal particles, carbon deposits, and acids that degrade its lubricating ability. Regular changes remove these contaminants and restore proper protection. Oil does not affect fuel octane or tire pressure.', true),
  ('AS-MNT-2', 'AS', 'as.maintenance-repair', 3, 'A vehicle''s brake pedal sinks slowly to the floor when held with steady pressure. This most likely indicates:', '["worn brake pads","a failing master cylinder or brake fluid leak","air in the fuel line","a loose wheel bearing"]'::jsonb, 1, 'A pedal that sinks under steady pressure (called brake fade or pedal drop) is a classic sign of a failing master cylinder or a leak allowing fluid to bypass the seals. Worn pads change stopping distance but do not cause the pedal to drop under held pressure.', true),
  ('AS-MNT-3', 'AS', 'as.maintenance-repair', 3, 'Tire rotation is recommended every 5,000–7,000 miles primarily because:', '["it resets the tire pressure monitoring system","front and rear tires wear at different rates due to different loads and steering forces","it prevents the tires from developing flat spots when parked","rotating tires improves fuel octane combustion"]'::jsonb, 1, 'Front tires handle steering forces and often support more weight from the engine, causing them to wear faster — especially on front-wheel-drive vehicles. Rotation equalizes wear across all four tires, extending overall tire life.', true),
  ('AS-MNT-4', 'AS', 'as.maintenance-repair', 4, 'When checking tire pressure, a technician should check it when the tires are:', '["hot, immediately after a long drive, for the most accurate reading","cold, before driving or after sitting for at least three hours","warm, after a short drive of about five miles","at any temperature, because modern gauges automatically adjust"]'::jsonb, 1, 'Tire pressure is specified for cold tires because driving heats air inside the tire, raising pressure by 4–8 psi. Checking hot tires gives a falsely high reading; the industry standard is to check cold tires. Modern gauges measure pressure but do not compensate for temperature.', true),
  ('AS-MNT-5', 'AS', 'as.maintenance-repair', 3, 'A vehicle pulls consistently to the right when driving on a straight, level road. The most likely cause is:', '["a clogged fuel filter","uneven tire pressure or a wheel alignment problem","a worn timing belt","low windshield washer fluid"]'::jsonb, 1, 'Pulling to one side is the classic symptom of uneven tire pressure or wheel misalignment. A low right-side tire or toe misalignment causes the vehicle to drift toward the low-pressure or angled side. Fuel and timing issues cause performance problems, not directional pull.', true),
  ('AS-MNT-6', 'AS', 'as.maintenance-repair', 4, 'A grinding noise that occurs only when the brakes are applied most likely indicates:', '["a failing alternator","brake pads worn down to the metal backing plate","loose lug nuts on the wheel","low power steering fluid"]'::jsonb, 1, 'When brake pad friction material wears away completely, the metal backing plate contacts the rotor directly, producing a grinding noise under braking. Alternator failure and low power steering fluid cause distinct, unrelated symptoms.', true),
  ('AS-MNT-7', 'AS', 'as.maintenance-repair', 4, 'The purpose of a vehicle''s PCV (Positive Crankcase Ventilation) valve is to:', '["regulate fuel injection timing","route blow-by gases from the crankcase back into the intake manifold for combustion","control coolant flow to the heater core","measure exhaust oxygen content for the fuel management system"]'::jsonb, 1, 'The PCV valve draws unburned gases (blow-by) that slip past piston rings back into the intake manifold where they are reburned. A stuck-closed PCV valve can build crankcase pressure and force oil past seals. The oxygen sensor (not PCV) measures exhaust oxygen.', true),
  ('AS-MNT-8', 'AS', 'as.maintenance-repair', 5, 'An engine runs rough at idle but smoothly at higher RPM. Disconnecting one spark plug wire at a time, you find that one cylinder makes no change to idle quality when its wire is removed. This means:', '["that cylinder is firing too often at idle","that cylinder is not contributing to engine power — it is misfiring or dead","the ignition coil for that cylinder is delivering extra voltage","all cylinders are sharing load equally"]'::jsonb, 1, 'Removing a plug wire from a healthy cylinder will cause idle to noticeably worsen. If removing a wire causes no change, that cylinder was already not contributing — it was misfiring. This test isolates the dead cylinder.', true),
  ('MC-IPH-1', 'MC', 'mc.inclined-plane-hydraulics', 3, 'A 300-pound crate is slid up a frictionless ramp that is 15 feet long and rises 5 feet vertically. How many pounds of force are required to push it up the ramp?', '["60 pounds","100 pounds","150 pounds","300 pounds"]'::jsonb, 1, 'Mechanical advantage of an inclined plane = length / height = 15 / 5 = 3. Required force = load / MA = 300 / 3 = 100 pounds. Using the full 300 pounds ignores the ramp''s advantage; 60 pounds would require MA of 5.', true),
  ('MC-IPH-2', 'MC', 'mc.inclined-plane-hydraulics', 3, 'In a hydraulic system, a small piston with an area of 2 square inches is pushed down with 50 pounds of force. What force does the large piston with an area of 10 square inches exert?', '["10 pounds","100 pounds","250 pounds","500 pounds"]'::jsonb, 2, 'Pascal''s principle: F₂/A₂ = F₁/A₁, so F₂ = F₁ × (A₂/A₁) = 50 × (10/2) = 50 × 5 = 250 pounds. The hydraulic system multiplies force in proportion to the area ratio.', true),
  ('MC-IPH-3', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A block-and-tackle pulley system uses 4 rope segments supporting the load. If you pull the free end with 75 pounds of force, how heavy a load can you lift (ignoring friction)?', '["75 pounds","150 pounds","225 pounds","300 pounds"]'::jsonb, 3, 'With 4 supporting rope segments, the mechanical advantage is 4. Lift capacity = effort × MA = 75 × 4 = 300 pounds. Each supporting strand shares the load equally, so more strands mean more force multiplication.', true),
  ('MC-IPH-4', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A hydraulic lift has an input piston area of 4 square inches and an output piston area of 20 square inches. If you need to lift 1,000 pounds, how much input force is required?', '["50 pounds","200 pounds","400 pounds","5,000 pounds"]'::jsonb, 1, 'Hydraulic MA = output area / input area = 20 / 4 = 5. Input force = load / MA = 1,000 / 5 = 200 pounds. Selecting 50 pounds corresponds to an MA of 20 (confusing areas with MA directly).', true),
  ('MC-IPH-5', 'MC', 'mc.inclined-plane-hydraulics', 4, 'A wedge is driven under one edge of a 500-pound boulder. The wedge is 8 inches long and 2 inches thick at its widest point. What is the mechanical advantage of this wedge?', '["2","4","6","250"]'::jsonb, 1, 'Mechanical advantage of a wedge = length / thickness = 8 / 2 = 4. A longer, thinner wedge provides greater advantage; the 500-pound load is the object being moved, not a factor in calculating MA.', true),
  ('MC-IPH-6', 'MC', 'mc.inclined-plane-hydraulics', 5, 'A 400-pound object must be raised 6 feet. You can use either a single fixed pulley, a ramp 18 feet long, or a hydraulic jack with a 5:1 area ratio. Ignoring friction, which requires the least input force?', '["single fixed pulley","the 18-foot ramp","the hydraulic jack","all three require identical force"]'::jsonb, 2, 'Single fixed pulley: MA = 1, force = 400 lbs. Ramp: MA = 18/6 = 3, force = 400/3 ≈ 133 lbs. Hydraulic jack: MA = 5, force = 400/5 = 80 lbs. The hydraulic jack requires the least force at 80 lbs.', true),
  ('MC-MOT-1', 'MC', 'mc.motion-projectile', 3, 'A 5-kg ball moving at 6 m/s collides with a stationary 5-kg ball and comes to a complete stop. What is the velocity of the second ball after the collision?', '["0 m/s","3 m/s","6 m/s","12 m/s"]'::jsonb, 2, 'Conservation of momentum: total momentum before = total momentum after. (5 × 6) + (5 × 0) = 30 kg·m/s. After: first ball stops, so second ball carries all momentum: 5 × v = 30, v = 6 m/s.', true),
  ('MC-MOT-2', 'MC', 'mc.motion-projectile', 3, 'An object is dropped from a height and falls freely under gravity (9.8 m/s²). After 3 seconds, its velocity is approximately:', '["9.8 m/s","19.6 m/s","29.4 m/s","44.1 m/s"]'::jsonb, 2, 'Velocity under free fall = g × t = 9.8 × 3 = 29.4 m/s. Each second adds 9.8 m/s of downward velocity; after 3 seconds the object is moving at 29.4 m/s.', true),
  ('MC-MOT-3', 'MC', 'mc.motion-projectile', 4, 'A net force of 20 N is applied to a 4-kg object. What is the object''s acceleration?', '["0.2 m/s²","5 m/s²","16 m/s²","80 m/s²"]'::jsonb, 1, 'Newton''s Second Law: a = F/m = 20/4 = 5 m/s². Dividing mass by force (4/20 = 0.2) inverts the formula, a common error. Multiplying gives 80, which misapplies the relationship.', true),
  ('MC-MOT-4', 'MC', 'mc.motion-projectile', 4, 'A ball is launched horizontally from a cliff at 20 m/s. Ignoring air resistance, what happens to the ball''s horizontal speed as it falls?', '["it increases because gravity accelerates it forward","it decreases because gravity slows horizontal motion","it stays constant because horizontal and vertical motions are independent","it reaches zero at peak height"]'::jsonb, 2, 'In projectile motion, horizontal and vertical components are independent. Gravity acts only vertically, so the horizontal speed remains 20 m/s throughout the flight. There is no peak height for a horizontally launched projectile — it only falls.', true),
  ('MC-MOT-5', 'MC', 'mc.motion-projectile', 4, 'Two identical hockey pucks rest on frictionless ice. Puck A is pushed with twice the force of Puck B for the same amount of time. Compared to Puck B, Puck A will have:', '["the same final velocity","twice the final velocity","four times the final velocity","half the final velocity"]'::jsonb, 1, 'Impulse = F × t = change in momentum. Same time, twice the force → twice the impulse → twice the change in momentum. Since masses are equal, twice the momentum means twice the velocity.', true),
  ('MC-MOT-6', 'MC', 'mc.motion-projectile', 5, 'A 10-kg object traveling at 4 m/s east collides and sticks to a 6-kg object traveling at 4 m/s west. What is the velocity of the combined mass after the collision?', '["4 m/s east","1 m/s east","0 m/s (they stop)","2.5 m/s west"]'::jsonb, 1, 'Momentum is a vector. Taking east as positive: p = (10 × 4) + (6 × −4) = 40 − 24 = 16 kg·m/s east. Combined mass = 16 kg. v = 16/16 = 1 m/s east. They don''t stop because the heavier object''s eastward momentum exceeds the lighter one''s westward momentum.', true),
  ('GS-PHY-1', 'GS', 'gs.physics-mechanics', 3, 'A book rests on a table without moving. According to Newton''s First Law, the book remains at rest because:', '["gravity is not acting on it","the table exerts an upward normal force that balances gravity","the book has no mass","friction from the table pushes the book upward"]'::jsonb, 1, 'Newton''s First Law states that an object at rest stays at rest when net force is zero. The table''s normal force (upward) exactly balances gravity (downward), producing zero net force. Friction acts horizontally and does not support the book''s weight.', true),
  ('GS-PHY-2', 'GS', 'gs.physics-mechanics', 3, 'Which simple machine is a screw most closely related to?', '["lever","wheel and axle","inclined plane","pulley"]'::jsonb, 2, 'A screw is essentially an inclined plane wrapped around a cylinder. The threads create a continuous spiral ramp, converting rotational force into linear motion. This is the same mechanical principle as a ramp, just in a circular form.', true),
  ('GS-PHY-3', 'GS', 'gs.physics-mechanics', 4, 'A person lifts a 60-Newton box 2 meters off the ground. How much work is done?', '["30 joules","62 joules","120 joules","240 joules"]'::jsonb, 2, 'Work = Force × Distance = 60 N × 2 m = 120 joules. Work is measured in joules (newton-meters). Dividing instead of multiplying gives 30 — a common sign-flip error. Adding (60 + 2 = 62) confuses the formula.', true),
  ('GS-PHY-4', 'GS', 'gs.physics-mechanics', 4, 'A compressed spring stores energy as:', '["kinetic energy","thermal energy","potential energy","chemical energy"]'::jsonb, 2, 'A compressed or stretched spring stores elastic potential energy — energy stored due to the object''s position or deformation. When released, potential energy converts to kinetic energy. Thermal energy would imply the spring heated up.', true),
  ('GS-PHY-5', 'GS', 'gs.physics-mechanics', 4, 'Two balls of different mass are dropped from the same height at the same time in a vacuum. Which hits the ground first?', '["the heavier ball, because gravity pulls it harder","the lighter ball, because it has less air resistance","they hit at the same time","it depends on the shape of each ball"]'::jsonb, 2, 'In a vacuum there is no air resistance. Gravity accelerates all objects equally regardless of mass (9.8 m/s²). This is what Galileo demonstrated — the common misconception is that heavier objects fall faster because gravity ''pulls harder,'' but acceleration is mass-independent.', true),
  ('GS-PHY-6', 'GS', 'gs.physics-mechanics', 5, 'A 500-W electric motor lifts a 200-N load vertically. How high can it lift the load in 4 seconds (ignoring friction)?', '["2.5 meters","5 meters","10 meters","40 meters"]'::jsonb, 2, 'Power = Work / Time, so Work = Power × Time = 500 × 4 = 2,000 joules. Work = Force × Distance, so Distance = Work / Force = 2,000 / 200 = 10 meters. Using 4 seconds as the distance (40 m) is a unit confusion error.', true),
  ('EI-CON-2', 'EI', 'ei.conductors-insulators', 3, 'A semiconductor differs from a conductor because a semiconductor:', '["conducts electricity under all conditions","never allows current to flow","conducts electricity only under certain conditions (such as added heat or doping)","has the same resistance as an insulator"]'::jsonb, 2, 'Semiconductors (like silicon and germanium) have electrical properties between conductors and insulators. Their conductivity can be controlled by temperature, light, or adding impurities (doping), which is why they are the basis of transistors and computer chips.', true),
  ('EI-CON-3', 'EI', 'ei.conductors-insulators', 4, 'Which of the following best explains why aluminum wire requires a larger gauge than copper wire to carry the same current safely?', '["aluminum is magnetic, which resists current flow","aluminum has higher resistivity than copper, so a larger cross-section is needed to reduce resistance","aluminum melts at a lower temperature and must be thicker for safety","aluminum has lower resistivity, making it harder for electrons to move"]'::jsonb, 1, 'Aluminum has about 1.6 times the resistivity of copper. To achieve the same resistance (and carry the same current without excessive heat), aluminum wire must have a larger cross-sectional area. This is why aluminum wiring uses larger gauges.', true),
  ('EI-CON-4', 'EI', 'ei.conductors-insulators', 4, 'Wet wood does not normally conduct electricity well, but wet wood with dissolved salts conducts much better. This demonstrates that:', '["wood becomes a semiconductor when cut","dissolved ions in water create charge carriers that enable conduction","heat from the salt lowers electrical resistance","salt acts as an insulator that traps electrons"]'::jsonb, 1, 'Pure water is a poor conductor, but dissolved salts (ionic compounds) break into positive and negative ions that can carry charge through the liquid. This is why saltwater and moist soil are better conductors than pure water alone.', true),
  ('EI-CON-5', 'EI', 'ei.conductors-insulators', 5, 'A technician handles a live wire while standing on a dry rubber mat. Why does the rubber mat protect the technician?', '["rubber absorbs excess electrical current and releases it as heat","rubber is an insulator that blocks the flow of current from the technician to ground","rubber becomes positively charged and repels electrons","rubber stores electrical charge, reducing voltage at the technician''s feet"]'::jsonb, 1, 'Electrical current flows along a complete circuit — from source, through a conductor, and back to ground. Rubber is an insulator; standing on it breaks the path to ground, preventing current from flowing through the technician''s body. This is why insulated footwear is required in electrical work.', true),
  ('EI-OHM-1', 'EI', 'ei.ohms-law-power', 3, 'A light bulb operates on 120 volts and draws 2 amperes. What is the power consumption of the bulb?', '["60 watts","122 watts","240 watts","480 watts"]'::jsonb, 2, 'Power = Voltage × Current = P = IV = 120 × 2 = 240 watts. Dividing (120/2 = 60) is the most common error — students confuse the power formula with Ohm''s Law for resistance.', true),
  ('EI-OHM-2', 'EI', 'ei.ohms-law-power', 3, 'Three resistors of 4 ohms, 6 ohms, and 2 ohms are connected in series. What is the total resistance of the circuit?', '["1 ohm","6 ohms","12 ohms","48 ohms"]'::jsonb, 2, 'In a series circuit, total resistance = R₁ + R₂ + R₃ = 4 + 6 + 2 = 12 ohms. The parallel formula (1/R) is often mistakenly applied here; in series, resistances simply add together.', true),
  ('EI-OHM-3', 'EI', 'ei.ohms-law-power', 4, 'A 12-volt battery powers a circuit with two resistors in series: 3 ohms and 1 ohm. What is the power dissipated by the 3-ohm resistor?', '["9 watts","12 watts","27 watts","36 watts"]'::jsonb, 2, 'Total resistance = 3 + 1 = 4 ohms. Current = V/R = 12/4 = 3 amperes. Power in the 3-ohm resistor: P = I²R = 3² × 3 = 9 × 3 = 27 watts. Using total voltage instead of calculating current first gives 48 W — a two-step problem requiring correct sequencing.', true),
  ('EI-OHM-4', 'EI', 'ei.ohms-law-power', 4, 'Two resistors are connected in parallel: one is 6 ohms and one is 3 ohms. What is the combined resistance?', '["9 ohms","4.5 ohms","2 ohms","1 ohm"]'::jsonb, 2, 'Parallel resistance formula: 1/R_total = 1/6 + 1/3 = 1/6 + 2/6 = 3/6 = 1/2. So R_total = 2 ohms. A common error is adding resistances as in series (6 + 3 = 9). In parallel, total resistance is always less than the smallest individual resistor.', true),
  ('EI-OHM-5', 'EI', 'ei.ohms-law-power', 5, 'A 9-volt battery powers a parallel circuit. Branch 1 has a 9-ohm resistor; Branch 2 has an 18-ohm resistor. What is the total current drawn from the battery?', '["0.5 amperes","1 ampere","1.5 amperes","3 amperes"]'::jsonb, 2, 'In parallel circuits, voltage across each branch equals source voltage. Branch 1 current: I₁ = 9/9 = 1 A. Branch 2 current: I₂ = 9/18 = 0.5 A. Total current = I₁ + I₂ = 1.5 A. Students who use combined parallel resistance alone often get the right answer but skip confirming via branch currents — here either method works.', true),
  ('AR-WRD-1', 'AR', 'ar.word-problems', 4, 'A supply truck can carry 4,800 pounds. It is loaded with boxes weighing 60 pounds each and crates weighing 120 pounds each. If there are 20 crates, how many boxes can also be loaded without exceeding the limit?', '["20 boxes","40 boxes","48 boxes","56 boxes"]'::jsonb, 1, 'Crates use: 20 × 120 = 2,400 lbs. Remaining capacity: 4,800 − 2,400 = 2,400 lbs. Number of boxes: 2,400 / 60 = 40 boxes. Dividing remaining capacity by 120 (crate weight) gives 20 — the error of using the wrong unit weight.', true),
  ('AR-WRD-2', 'AR', 'ar.word-problems', 4, 'A fuel tank is 3/4 full and holds 24 gallons at that level. How many total gallons does the tank hold when completely full?', '["18 gallons","30 gallons","32 gallons","36 gallons"]'::jsonb, 2, 'If 3/4 of the tank = 24 gallons, then 1/4 = 8 gallons, and the full tank = 4 × 8 = 32 gallons. Multiplying 24 × (3/4) = 18 gallons is the reverse error — treating the fraction as a multiplier instead of recognizing it represents the current fill level.', true),
  ('AR-PCT-1', 'AR', 'ar.percent', 4, 'A piece of equipment originally cost $800. After a 15% discount it was purchased, then later sold for 10% more than the purchase price. What was the final selling price?', '["$748.00","$756.00","$770.00","$792.00"]'::jsonb, 0, 'Apply percentages sequentially: $800 × (1 − 0.15) = $680, then $680 × (1 + 0.10) = $748. Common error: netting the percentages to −5% gives $760, which is wrong because each percent applies to a different base.', true),
  ('AR-RAT-1', 'AR', 'ar.ratio-proportion', 4, 'A military convoy travels 120 miles in 2.5 hours. At the same rate, how far will it travel in 4 hours?', '["160 miles","192 miles","200 miles","240 miles"]'::jsonb, 1, 'Speed = 120 / 2.5 = 48 mph. Distance in 4 hours = 48 × 4 = 192 miles. Multiplying 120 × 4 = 480 ignores the rate calculation; 200 miles results from rounding 48 to 50 mph.', true),
  ('AR-ALG-1', 'AR', 'ar.arithmetic-fundamentals', 5, 'A storage room has 3 shelves. Each shelf holds twice as many items as the shelf below it. The bottom shelf holds 15 items. How many items are in the storage room in total?', '["45 items","90 items","105 items","120 items"]'::jsonb, 2, 'Bottom shelf: 15. Middle shelf: 15 × 2 = 30. Top shelf: 30 × 2 = 60. Total = 15 + 30 + 60 = 105 items. Adding 15 three times (45) misses the doubling; multiplying all by 2 once (30 × 3 = 90) misapplies the doubling pattern.', true),
  ('MK-ALG-1', 'MK', 'mk.algebra-linear', 4, 'If 5(x − 3) = 2x + 6, what is the value of x?', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 2, 'Distribute: 5x − 15 = 2x + 6. Subtract 2x: 3x − 15 = 6. Add 15: 3x = 21. x = 7. A common error is failing to distribute the 5 to −3, giving 5x − 3 = 2x + 6 and solving to x = 3.', true),
  ('MK-GEO-1', 'MK', 'mk.geometry', 4, 'A cylindrical water tank has a radius of 3 feet and a height of 10 feet. What is its volume? (Use π ≈ 3.14)', '["94.2 cubic feet","188.4 cubic feet","282.6 cubic feet","942 cubic feet"]'::jsonb, 2, 'Volume of a cylinder = π × r² × h = 3.14 × 9 × 10 = 282.6 cubic feet. Using diameter (6) instead of radius (3) gives 3.14 × 36 × 10 = 1,130.4 — squaring the diameter is the most common error. Using r = 3 without squaring gives 3.14 × 3 × 10 = 94.2.', true),
  ('MK-FRC-1', 'MK', 'mk.fractions-decimals', 5, 'A fuel mixture is 2/5 diesel and the rest is gasoline. If the tank holds 60 liters, how many more liters of gasoline than diesel does it contain?', '["12 liters more gasoline","24 liters more gasoline","12 liters more diesel","36 liters more gasoline"]'::jsonb, 0, 'Diesel = (2/5) × 60 = 24 liters. Gasoline = 60 − 24 = 36 liters. Difference = 36 − 24 = 12 liters more gasoline. Choosing 24 liters confuses the diesel volume with the difference; choosing 36 liters is the gasoline volume, not the difference between the two.', true),
  ('WK-CTX-HARD-1', 'WK', 'wk.context-clues', 5, 'In the sentence ''The politician''s OBSEQUIOUS deference to every donor in the room struck journalists as calculated rather than genuine,'' the word OBSEQUIOUS most nearly means:', '["bold and outspoken","excessively eager to please or serve","professionally courteous","openly hostile"]'::jsonb, 1, 'Obsequious means servilely compliant or fawning — behaving in an excessively eager-to-please way. The clue that it ''struck journalists as calculated'' confirms it goes beyond normal professional courtesy, ruling out choice C. Bold or hostile are direct opposites.', true),
  ('WK-SYN-HARD-1', 'WK', 'wk.synonyms', 4, 'EPHEMERAL most nearly means:', '["ancient","lasting only a short time","extraordinarily rare","deeply emotional"]'::jsonb, 1, 'Ephemeral means lasting for a very short time (from Greek ephemeros, ''for a day''). Ancient is essentially its opposite. Rare and emotional are unrelated to its core meaning of brevity.', true),
  ('WK-SYN-HARD-2', 'WK', 'wk.synonyms', 5, 'VERACIOUS most nearly means:', '["extremely hungry","truthful","speedy","aggressive"]'::jsonb, 1, 'Veracious means habitually speaking the truth. It is commonly confused with voracious (extremely hungry), which sounds similar. The VER- root relates to truth (verify, veracity), while VOR- relates to eating (devour).', true),
  ('PC-INF-HARD-1', 'PC', 'pc.inference', 4, 'Read the passage below and answer the question.

"The lab''s results were submitted three times before the review board accepted them. Each submission included additional documentation requested by the board, yet the board raised new objections with each round. When the research was finally published, it overturned a theory the board''s chair had authored fifteen years earlier. The chair did not recuse himself from the review."

What can most reasonably be inferred from this passage?', '["The research contained significant methodological flaws that required correction.","The board''s repeated objections may have been influenced by a conflict of interest.","Government agencies routinely require three rounds of submission for new research.","The board chair ultimately supported the research once it was explained clearly."]'::jsonb, 1, 'The detail that the board kept finding new objections — and that the final research contradicted the chair''s own published theory — strongly implies a conflict of interest. Choice A is contradicted by the research''s eventual publication. Choices C and D are not supported by any passage detail.', true),
  ('PC-MAIN-HARD-1', 'PC', 'pc.main-idea', 4, 'Read the passage below and answer the question.

"Maps are not neutral documents. Every map involves choices: what to include, what to omit, which areas to enlarge, and which projection to use. The Mercator projection, still common in classrooms, inflates the size of land near the poles — making Greenland appear as large as Africa, when Africa is actually fourteen times larger. A map teaches not just geography but a way of seeing the world."

What is the main idea of this passage?', '["The Mercator projection is the most accurate map projection available.","Maps reflect decisions and assumptions that shape how people perceive the world.","Africa is fourteen times larger than Greenland.","Classroom maps should be replaced with digital navigation tools."]'::jsonb, 1, 'The passage opens and closes with the argument that maps embed choices and teach a ''way of seeing.'' The Greenland/Africa fact is supporting evidence, not the main point. Choice D is never mentioned; Choice A contradicts the passage''s argument.', true),
  ('MK-ALG-HARD-1', 'MK', 'mk.algebra-linear', 5, 'Depot A charges a $40 setup fee plus $12 per unit ordered. Depot B charges no setup fee but $16 per unit. At exactly how many units do the two depots cost the same?', '["5 units","8 units","10 units","12 units"]'::jsonb, 2, 'Set costs equal: 40 + 12n = 16n. Subtract 12n from both sides: 40 = 4n. Divide: n = 10 units. At 10 units: Depot A = 40 + 120 = $160; Depot B = 16 × 10 = $160. Confirm equal. A common error is setting up the equation as 40 + 16n = 12n, which gives a negative n because the student reverses which depot has the base fee.', true),
  ('MK-GEO-HARD-1', 'MK', 'mk.geometry', 4, 'A right triangle has legs of 9 and 12. What is the length of the hypotenuse?', '["13","15","17","21"]'::jsonb, 1, 'Pythagorean theorem: c² = 9² + 12² = 81 + 144 = 225. c = √225 = 15. This is a classic 3-4-5 triple scaled by 3 (9-12-15). Adding the legs (9 + 12 = 21) or averaging them are common wrong approaches.', true),
  ('AR-PCT-HARD-1', 'AR', 'ar.percent', 5, 'A soldier scores 72 on a first test and 88 on a second test. What is the percent increase from the first score to the second score, rounded to the nearest whole percent?', '["16%","18%","22%","25%"]'::jsonb, 2, 'Percent increase = (new − old) / old × 100 = (88 − 72) / 72 × 100 = 16/72 × 100 ≈ 22.2%, rounded to 22%. Dividing by the new score (16/88 ≈ 18%) is the most common error — percent change always uses the original value as the base.', true),
  ('WK-CTX-D2-1', 'WK', 'wk.context-clues', 2, 'In the sentence ''The trail looked safe but proved TREACHEROUS, with hidden drop-offs and unstable footing,'' the word TREACHEROUS most nearly means:', '["deceptively dangerous","exhausting","remote","unfamiliar"]'::jsonb, 0, 'Treacherous means deceptively dangerous — something that appears safe but conceals serious hazards. The new stem reinforces this with ''hidden drop-offs and unstable footing.'' Exhausting, remote, and unfamiliar describe possible trail qualities but do not capture the deceptive, unpredictable danger that treacherous conveys.', true),
  ('WK-PFX-D2-1', 'WK', 'wk.prefixes-suffixes', 2, 'The prefix MIS- means wrongly or badly. MISJUDGE therefore means:', '["to judge again","to judge fairly","to judge wrongly","to refuse to judge"]'::jsonb, 2, 'MIS- attaches to a verb and means wrongly or badly — as in mislead (lead wrongly), misfire (fire at wrong time), misuse. Misjudge means to form an incorrect judgment.', true),
  ('AS-MNT-D2-1', 'AS', 'as.maintenance-repair', 2, 'Why is it important to check the coolant level in a vehicle''s radiator regularly?', '["Low coolant improves fuel economy","Low coolant can cause the engine to overheat","Coolant affects the transmission shift points","Coolant level determines oil viscosity"]'::jsonb, 1, 'Engine coolant carries heat away from the engine block to the radiator. If the level drops too low, there is insufficient fluid to absorb engine heat, and the engine can overheat — causing serious damage such as a warped head gasket.', true),
  ('GS-PHY-D2-1', 'GS', 'gs.physics-mechanics', 2, 'Which of the following is an example of potential energy?', '["a spinning fan blade","a rock sitting on a high cliff","a car moving at 60 mph","sound traveling through air"]'::jsonb, 1, 'Potential energy is stored energy due to an object''s position or condition. A rock on a cliff has gravitational potential energy because of its height. The other options describe energy in motion (kinetic) or wave energy.', true),
  ('MC-MOT-D2-1', 'MC', 'mc.motion-projectile', 2, 'Newton''s First Law states that an object in motion stays in motion unless acted on by an outside force. Which of the following best demonstrates this law?', '["a ball speeding up as it rolls downhill","a hockey puck sliding across frictionless ice at constant speed","a rocket accelerating after launch","a pendulum slowing down due to air resistance"]'::jsonb, 1, 'Newton''s First Law describes inertia: no net force means no change in motion. A puck on frictionless ice has no friction or other horizontal force acting on it, so it maintains constant speed — the purest illustration of the law. The pendulum example actually shows the law being violated by air resistance.', true),
  ('EI-OHM-D2-1', 'EI', 'ei.ohms-law-power', 2, 'A circuit has a resistance of 8 ohms and a current of 3 amperes flowing through it. What is the voltage across the circuit?', '["2.7 volts","11 volts","24 volts","64 volts"]'::jsonb, 2, 'Ohm''s Law: V = I × R = 3 × 8 = 24 volts. Dividing instead of multiplying (8 / 3 ≈ 2.7) is the most common error. Adding (3 + 8 = 11) confuses the formula entirely.', true),
  ('MK-GEO-D2-1', 'MK', 'mk.geometry', 2, 'What is the perimeter of a rectangle that is 8 feet long and 5 feet wide?', '["13 feet","26 feet","40 feet","80 feet"]'::jsonb, 1, 'Perimeter = 2 × (length + width) = 2 × (8 + 5) = 2 × 13 = 26 feet. A common error is adding all four sides without doubling (8 + 5 = 13) or multiplying length by width to get area (40 square feet) instead of perimeter.', true),
  ('AR-AF-1', 'AR', 'ar.arithmetic-fundamentals', 3, 'A crate holds 24 bottles. A store receives 15 crates. After selling 120 bottles, how many bottles remain?', '["120","180","240","300"]'::jsonb, 2, 'Total = 24 × 15 = 360 bottles. 360 − 120 = 240 remain. The trap is computing 24 × 12 = 288 by misreading the crate count.', true),
  ('AR-AF-2', 'AR', 'ar.arithmetic-fundamentals', 3, 'A soldier buys 4 notebooks at $3 each and 6 pens at $1.25 each. What is the total cost?', '["$16.50","$17.50","$18.75","$19.50"]'::jsonb, 3, 'Notebooks: 4 × $3 = $12. Pens: 6 × $1.25 = $7.50. Total = $12 + $7.50 = $19.50.', true),
  ('AR-AF-3', 'AR', 'ar.arithmetic-fundamentals', 4, 'A truck can carry 850 pounds. A soldier loads 10 boxes at 75 pounds each. How many pounds of capacity remain?', '["75","100","125","150"]'::jsonb, 1, '10 boxes × 75 lb = 750 lb loaded. Remaining capacity = 850 − 750 = 100 lb.', true),
  ('AR-AF-4', 'AR', 'ar.arithmetic-fundamentals', 3, 'A barracks has 6 rooms, each holding 4 soldiers. If 14 soldiers are currently assigned, how many empty beds remain?', '["6","8","10","14"]'::jsonb, 2, 'Total beds = 6 × 4 = 24. Empty = 24 − 14 = 10.', true),
  ('AR-AF-5', 'AR', 'ar.arithmetic-fundamentals', 4, 'A soldier earns $2,880 per month. After paying $720 in rent and $340 in other bills, she saves the rest. How much does she save over 4 months?', '["$1,820","$6,400","$7,280","$11,520"]'::jsonb, 2, 'Monthly savings = $2,880 − $720 − $340 = $1,820. Over 4 months: $1,820 × 4 = $7,280.', true),
  ('AR-RP-1', 'AR', 'ar.ratio-proportion', 3, 'A recipe uses 3 cups of flour for every 2 cups of sugar. How many cups of sugar are needed if you use 12 cups of flour?', '["6","8","9","18"]'::jsonb, 1, 'Flour:Sugar = 3:2. Sugar = (2/3) × 12 = 8 cups. The trap is flipping the ratio and using 3/2 × 12 = 18.', true),
  ('AR-RP-2', 'AR', 'ar.ratio-proportion', 3, 'The exchange rate is 1 U.S. dollar = 0.85 euros. A soldier converts $240 to euros. How many euros does she receive?', '["180","196","204","282"]'::jsonb, 2, 'Euros = 240 × 0.85 = 204. The trap answer 282 comes from dividing 240 ÷ 0.85, which is converting in the wrong direction.', true),
  ('AR-RP-4', 'AR', 'ar.ratio-proportion', 5, 'A squad of 12 soldiers can build a wall in 8 hours. How long will it take a squad of 16 soldiers to build the same wall at the same work rate?', '["4 hours","5 hours","6 hours","7 hours"]'::jsonb, 2, 'Total work = 12 × 8 = 96 soldier-hours. With 16 soldiers: 96 ÷ 16 = 6 hours. This is inverse proportion — more workers means less time.', true),
  ('AR-RP-5', 'AR', 'ar.ratio-proportion', 4, 'A kitchen uses oil and vinegar in a 5:3 ratio to make dressing. A cook needs 64 ounces of dressing total. How many ounces of vinegar are needed?', '["16","20","24","40"]'::jsonb, 2, 'Vinegar = (3/8) × 64 = 24 ounces. The trap is using 3/5 of 64 = 38.4, or thinking vinegar is the larger portion.', true),
  ('AR-RP-6', 'AR', 'ar.ratio-proportion', 3, 'A kitchen uses salt and pepper in a ratio of 4:1 by weight. If a cook uses 20 grams of salt, how many grams of pepper are needed?', '["4","5","8","16"]'::jsonb, 1, 'Pepper = (1/4) × 20 = 5 grams.', true),
  ('AR-RP-7', 'AR', 'ar.ratio-proportion', 4, 'A supply truck carries canned goods and dry goods in a 3:5 ratio by weight. The total shipment weighs 640 pounds. How many pounds of canned goods are delivered?', '["160","200","240","400"]'::jsonb, 2, 'Total parts = 3 + 5 = 8. Each part = 640 ÷ 8 = 80 lb. Canned goods = 3 × 80 = 240 lb. The trap is using 3/5 of 640 = 384.', true),
  ('AR-PC-1', 'AR', 'ar.percent', 3, 'A jacket originally costs $80. It is on sale for 25% off. What is the sale price?', '["$20","$55","$60","$65"]'::jsonb, 2, 'Discount = 25% × $80 = $20. Sale price = $80 − $20 = $60.', true),
  ('AR-PC-2', 'AR', 'ar.percent', 3, 'A soldier''s physical fitness score increased from 60 to 75. What is the percent increase?', '["15%","20%","25%","30%"]'::jsonb, 2, 'Percent increase = (75 − 60) / 60 × 100 = 15/60 × 100 = 25%. The trap is dividing by the new value 75 to get 20%.', true),
  ('AR-PC-3', 'AR', 'ar.percent', 4, 'A meal costs $36. A 15% tip and a separate 10% service fee are both applied to the original $36 bill. What is the total amount paid?', '["$40.68","$43.20","$45.00","$45.36"]'::jsonb, 2, 'Tip = 15% × $36 = $5.40. Service fee = 10% × $36 = $3.60. Total = $36 + $5.40 + $3.60 = $45.00. The trap is compounding the service fee onto the tipped price.', true),
  ('AR-PC-4', 'AR', 'ar.percent', 3, 'A soldier invests $1,000 at 6% simple annual interest. How much interest is earned after 3 years?', '["$60","$180","$191","$600"]'::jsonb, 1, 'Simple interest = Principal × Rate × Time = $1,000 × 0.06 × 3 = $180. The trap is computing only 1 year''s interest ($60) or applying compound interest.', true),
  ('AR-PC-5', 'AR', 'ar.percent', 4, 'A store marks up a $50 item by 20%, then offers a 10% discount on the marked-up price. What is the final selling price?', '["$50.00","$54.00","$55.00","$58.00"]'::jsonb, 1, 'Marked-up price = $50 × 1.20 = $60. After 10% discount: $60 × 0.90 = $54. The trap is thinking +20% then −10% nets +10%, giving $55.', true),
  ('AR-PC-6', 'AR', 'ar.percent', 3, 'A town''s population grew from 4,000 to 4,600 in one year. What was the percent increase?', '["12.5%","13%","15%","16%"]'::jsonb, 2, 'Percent increase = (600 ÷ 4,000) × 100 = 15%.', true),
  ('AR-RD-1', 'AR', 'ar.rate-distance-time', 3, 'A soldier runs at 6 miles per hour. How far does she run in 45 minutes?', '["3.5 miles","4 miles","4.5 miles","5 miles"]'::jsonb, 2, '45 minutes = 0.75 hours. Distance = 6 × 0.75 = 4.5 miles.', true),
  ('AR-RD-2', 'AR', 'ar.rate-distance-time', 4, 'Two convoys leave the same base traveling in opposite directions. One travels at 45 mph and the other at 55 mph. How far apart are they after 2 hours?', '["90 miles","110 miles","180 miles","200 miles"]'::jsonb, 3, 'Combined separation rate = 45 + 55 = 100 mph. Distance apart = 100 × 2 = 200 miles. The trap is using only one convoy''s speed.', true),
  ('AR-RD-3', 'AR', 'ar.rate-distance-time', 4, 'Pump A fills a tank at 40 gallons per minute. Pump B drains it at 15 gallons per minute. Starting empty, how many minutes until a 1,000-gallon tank is full with both pumps running?', '["25 minutes","33 minutes","40 minutes","67 minutes"]'::jsonb, 2, 'Net fill rate = 40 − 15 = 25 gal/min. Time = 1,000 ÷ 25 = 40 minutes.', true),
  ('AR-RD-4', 'AR', 'ar.rate-distance-time', 3, 'A vehicle travels 180 miles in 3 hours. At the same speed, how long will it take to travel 270 miles?', '["3.5 hours","4 hours","4.5 hours","5 hours"]'::jsonb, 2, 'Speed = 180 ÷ 3 = 60 mph. Time for 270 miles = 270 ÷ 60 = 4.5 hours.', true),
  ('AR-RD-5', 'AR', 'ar.rate-distance-time', 5, 'Soldier A can complete a course in 4 hours alone. Soldier B can complete the same course in 6 hours alone. Working together, how long do they take?', '["2 hours","2 hours 24 minutes","3 hours","3 hours 20 minutes"]'::jsonb, 1, 'Combined rate = 1/4 + 1/6 = 3/12 + 2/12 = 5/12 per hour. Time = 12/5 = 2.4 hours = 2 hours 24 minutes.', true),
  ('AR-RD-6', 'AR', 'ar.rate-distance-time', 3, 'A helicopter flies 420 miles at 140 mph. How long does the flight take?', '["2 hours","2.5 hours","3 hours","3.5 hours"]'::jsonb, 2, 'Time = Distance ÷ Speed = 420 ÷ 140 = 3 hours.', true),
  ('AR-WP-1', 'AR', 'ar.word-problems', 4, 'A soldier spends 1/3 of his monthly pay on rent and 1/4 on food, and saves the rest. His monthly pay is $2,400. How much does he save each month?', '["$400","$600","$800","$1,000"]'::jsonb, 3, 'Rent = 1/3 × $2,400 = $800. Food = 1/4 × $2,400 = $600. Savings = $2,400 − $800 − $600 = $1,000.', true),
  ('AR-WP-2', 'AR', 'ar.word-problems', 5, 'Three soldiers share a $420 supply order. One soldier pays twice as much as each of the other two. How much does the soldier paying more contribute?', '["$105","$140","$168","$210"]'::jsonb, 3, 'Let each of the two pay x. The third pays 2x. Equation: x + x + 2x = 4x = $420, so x = $105. The larger share = 2x = $210.', true),
  ('AR-WP-3', 'AR', 'ar.word-problems', 3, 'A base has 480 personnel. If 35% are on leave, how many are currently on base?', '["148","168","288","312"]'::jsonb, 3, 'On leave = 35% × 480 = 168. On base = 480 − 168 = 312. The trap is selecting 168 (those on leave) rather than those remaining.', true),
  ('AR-WP-4', 'AR', 'ar.word-problems', 4, 'A mess hall serves breakfast for 2 hours at 80 soldiers per hour and lunch for 3 hours at 120 soldiers per hour. What is the total number of soldiers served?', '["400","500","520","600"]'::jsonb, 2, 'Breakfast = 80 × 2 = 160. Lunch = 120 × 3 = 360. Total = 160 + 360 = 520.', true),
  ('AR-WP-5', 'AR', 'ar.word-problems', 4, 'A soldier drives 3 legs of a trip: 60 miles at 30 mph, then 120 miles at 60 mph, then 90 miles at 45 mph. What is the total driving time?', '["5 hours","5.5 hours","6 hours","6.5 hours"]'::jsonb, 2, 'Leg 1: 60 ÷ 30 = 2 hrs. Leg 2: 120 ÷ 60 = 2 hrs. Leg 3: 90 ÷ 45 = 2 hrs. Total = 6 hours.', true),
  ('AR-WP-6', 'AR', 'ar.word-problems', 3, 'A soldier''s monthly pay is $3,000. She receives a 5% pay raise. What is her new monthly pay?', '["$3,050","$3,100","$3,150","$3,200"]'::jsonb, 2, 'Raise = 5% × $3,000 = $150. New pay = $3,000 + $150 = $3,150.', true),
  ('MK-AL-1', 'MK', 'mk.algebra-linear', 3, 'Solve for x: 3x + 7 = 22', '["x = 3","x = 5","x = 7","x = 9"]'::jsonb, 1, '3x = 22 − 7 = 15. x = 15 ÷ 3 = 5.', true),
  ('MK-AL-2', 'MK', 'mk.algebra-linear', 3, 'Solve for x: 4x − 9 = 23', '["x = 3.5","x = 7","x = 8","x = 32"]'::jsonb, 2, '4x = 23 + 9 = 32. x = 32 ÷ 4 = 8.', true),
  ('MK-AL-3', 'MK', 'mk.algebra-linear', 5, 'Solve the system: 2x + y = 11 and x − y = 1. What is the value of x?', '["x = 2","x = 3","x = 4","x = 5"]'::jsonb, 2, 'Add both equations: (2x + y) + (x − y) = 11 + 1 → 3x = 12 → x = 4. Then y = x − 1 = 3. Verify: 2(4) + 3 = 11 ✓.', true),
  ('MK-AL-4', 'MK', 'mk.algebra-linear', 4, 'Which value of x satisfies the inequality 5x − 4 > 16?', '["x = 3","x = 4","x = 4.5","x = 5"]'::jsonb, 3, '5x > 16 + 4 = 20, so x > 4. Among the choices, only x = 5 satisfies x > 4.', true),
  ('MK-AL-5', 'MK', 'mk.algebra-linear', 3, 'If 2(x + 3) = 18, what is x?', '["x = 6","x = 7","x = 9","x = 12"]'::jsonb, 0, 'Distribute: 2x + 6 = 18. 2x = 12. x = 6.', true),
  ('MK-AL-6', 'MK', 'mk.algebra-linear', 4, 'A soldier earns $d per day. After 5 days he has earned $650. He spends $200. Which expression correctly gives his remaining money?', '["5d − 200","d/5 − 200","650 − 5d","5(d − 200)"]'::jsonb, 0, 'Total earned after 5 days = 5d. Since 5d = $650, he then spends $200, leaving 5d − 200 = 650 − 200 = $450. The expression 5d − 200 models earning then spending.', true),
  ('MK-FR-1', 'MK', 'mk.fractions-decimals', 3, 'What is 3/4 + 2/3?', '["5/7","5/12","1 5/12","1 7/12"]'::jsonb, 2, 'Common denominator is 12. 3/4 = 9/12; 2/3 = 8/12. Sum = 17/12 = 1 5/12. The trap is adding numerators and denominators directly to get 5/7.', true),
  ('MK-FR-2', 'MK', 'mk.fractions-decimals', 3, 'Which fraction is largest: 5/8, 2/3, 3/5, or 7/12?', '["5/8","2/3","3/5","7/12"]'::jsonb, 1, 'Convert to a common denominator of 120: 5/8 = 75/120, 2/3 = 80/120, 3/5 = 72/120, 7/12 = 70/120. Largest is 2/3.', true),
  ('MK-FR-3', 'MK', 'mk.fractions-decimals', 4, 'A soldier runs 2.75 miles on Monday and 1 3/4 miles on Tuesday. What is the combined distance?', '["4.00 miles","4.25 miles","4.50 miles","4.75 miles"]'::jsonb, 2, '1 3/4 = 1.75 miles. Total = 2.75 + 1.75 = 4.50 miles.', true),
  ('MK-FR-4', 'MK', 'mk.fractions-decimals', 3, 'What is (3/5) × (10/9)?', '["1/3","2/3","6/5","5/3"]'::jsonb, 1, 'Multiply numerators and denominators: (3 × 10) / (5 × 9) = 30/45 = 2/3 in lowest terms. The trap ‘5/3’ is what students get when they invert the wrong fraction and multiply — flipping 10/9 to 9/10 then computing (3/5) × (9/10)? No: the inversion error is treating multiplication like division, giving 3/5 ÷ 10/9 = (3/5) × (9/10) = 27/50, or more simply, students who flip both fractions get (5/3) × (9/10) and then lose track. The key takeaway: multiply straight across, then simplify.', true),
  ('MK-FR-5', 'MK', 'mk.fractions-decimals', 4, 'Express 0.625 as a fraction in lowest terms.', '["5/8","6/10","25/40","3/5"]'::jsonb, 0, '0.625 = 625/1000. Divide by GCF 125: 5/8. Options 6/10 and 25/40 are equivalent but not fully reduced; 3/5 = 0.60 ≠ 0.625.', true),
  ('MK-EP-1', 'MK', 'mk.exponents-polynomials', 3, 'Simplify: 2³ × 2⁴', '["2⁶","2⁷","4⁷","8⁷"]'::jsonb, 1, 'When multiplying powers with the same base, add the exponents: 2³ × 2⁴ = 2^(3+4) = 2⁷ = 128.', true),
  ('MK-EP-2', 'MK', 'mk.exponents-polynomials', 3, 'What is (3²)³?', '["3⁵","3⁶","9³","27²"]'::jsonb, 1, 'Power of a power rule: multiply the exponents. (3²)³ = 3^(2×3) = 3⁶ = 729. The trap is adding instead of multiplying to get 3⁵.', true),
  ('MK-EP-3', 'MK', 'mk.exponents-polynomials', 4, 'Expand and simplify: (x + 4)(x − 3)', '["x² − 12","x² + x − 12","x² − x − 12","x² + 7x − 12"]'::jsonb, 1, 'FOIL: x·x + x·(−3) + 4·x + 4·(−3) = x² − 3x + 4x − 12 = x² + x − 12.', true),
  ('MK-EP-4', 'MK', 'mk.exponents-polynomials', 4, 'Factor: x² − 9', '["(x − 3)²","(x + 3)(x − 3)","(x − 9)(x + 1)","(x + 9)(x − 1)"]'::jsonb, 1, 'This is a difference of squares: x² − 9 = x² − 3² = (x + 3)(x − 3). The trap (x − 3)² expands to x² − 6x + 9, not x² − 9.', true),
  ('MK-EP-5', 'MK', 'mk.exponents-polynomials', 4, 'Simplify: (4x³y²) ÷ (2xy)', '["2x²y","2x³y","4x²y","2x²y²"]'::jsonb, 0, 'Coefficients: 4 ÷ 2 = 2. x-terms: x³ ÷ x = x². y-terms: y² ÷ y = y. Result: 2x²y.', true),
  ('MK-GE-1', 'MK', 'mk.geometry', 3, 'A rectangular field is 80 meters long and 35 meters wide. What is its perimeter?', '["115 m","230 m","270 m","2,800 m"]'::jsonb, 1, 'Perimeter = 2(l + w) = 2(80 + 35) = 2(115) = 230 m. The trap is computing l + w once (115 m) without multiplying by 2.', true),
  ('MK-GE-2', 'MK', 'mk.geometry', 3, 'A triangle has a base of 14 cm and a height of 9 cm. What is its area?', '["46 cm²","63 cm²","126 cm²","252 cm²"]'::jsonb, 1, 'Area = (1/2) × base × height = (1/2) × 14 × 9 = 63 cm². The trap is omitting the 1/2 factor, giving 126 cm².', true),
  ('MK-GE-3', 'MK', 'mk.geometry', 4, 'A cylinder has a radius of 5 cm and a height of 10 cm. What is its volume? (Use π ≈ 3.14)', '["157 cm³","314 cm³","785 cm³","1,570 cm³"]'::jsonb, 2, 'V = πr²h = 3.14 × 5² × 10 = 3.14 × 25 × 10 = 785 cm³. Using the diameter (10) as the radius gives 3.14 × 100 × 10 = 3,140 — a common error.', true),
  ('MK-GE-4', 'MK', 'mk.geometry', 3, 'A circle has a diameter of 10 cm. What is its area? (Use π ≈ 3.14)', '["31.4 cm²","62.8 cm²","78.5 cm²","314 cm²"]'::jsonb, 2, 'Radius = diameter ÷ 2 = 5 cm. Area = πr² = 3.14 × 25 = 78.5 cm². Using the diameter as the radius gives 3.14 × 100 = 314 — a classic trap.', true),
  ('MK-NP-1', 'MK', 'mk.number-properties', 3, 'Which of the following is a prime number?', '["51","57","61","91"]'::jsonb, 2, '51 = 3 × 17; 57 = 3 × 19; 91 = 7 × 13. Only 61 has no factors besides 1 and itself, so it is prime.', true),
  ('MK-NP-2', 'MK', 'mk.number-properties', 3, 'What is the greatest common factor (GCF) of 36 and 48?', '["6","9","12","18"]'::jsonb, 2, 'Factors of 36 include 1, 2, 3, 4, 6, 9, 12, 18, 36. Factors of 48 include 1, 2, 3, 4, 6, 8, 12, 16, 24, 48. The largest common factor is 12.', true),
  ('MK-NP-3', 'MK', 'mk.number-properties', 4, 'The product of two consecutive even integers is 48. What is the smaller integer?', '["4","6","8","10"]'::jsonb, 1, 'Let the integers be n and n + 2. n(n + 2) = 48. Try n = 6: 6 × 8 = 48. ✓ The smaller integer is 6.', true),
  ('MK-NP-4', 'MK', 'mk.number-properties', 4, 'A number N is divisible by both 6 and 10. What is the smallest positive value N can be?', '["16","30","60","120"]'::jsonb, 1, 'The least common multiple (LCM) of 6 and 10 is found using prime factors: 6 = 2 × 3, 10 = 2 × 5. LCM = 2 × 3 × 5 = 30. The trap is multiplying 6 × 10 = 60.', true),
  ('WK-SN-2', 'WK', 'wk.synonyms', 2, 'TRANQUIL most nearly means:', '["Noisy","Peaceful","Rushed","Dangerous"]'::jsonb, 1, 'Tranquil means free from disturbance; calm and peaceful.', true),
  ('WK-SN-5', 'WK', 'wk.synonyms', 3, 'LETHARGIC most nearly means:', '["Energetic","Sluggish","Aggressive","Focused"]'::jsonb, 1, 'Lethargic means lacking energy or enthusiasm; sluggish. Energetic is its antonym.', true),
  ('WK-SN-6', 'WK', 'wk.synonyms', 4, 'INSCRUTABLE most nearly means:', '["Mysterious","Obvious","Unreliable","Talkative"]'::jsonb, 0, 'Inscrutable means impossible to understand or interpret; mysterious. The root ''scrutin-'' means to examine — inscrutable means it cannot be read through.', true),
  ('WK-SN-7', 'WK', 'wk.synonyms', 4, 'OBSEQUIOUS most nearly means:', '["Stubborn","Fawning","Rebellious","Indifferent"]'::jsonb, 1, 'Obsequious means excessively eager to serve or please; sycophantic. Recruits often confuse it with obstinate (stubborn) because of the similar opening sounds.', true),
  ('WK-SN-8', 'WK', 'wk.synonyms', 4, 'MAGNANIMOUS most nearly means:', '["Generous","Arrogant","Petty","Powerful"]'::jsonb, 0, 'Magnanimous means nobly generous or forgiving, especially toward an enemy. From Latin magna (great) + animus (spirit). Do not confuse with magnificent.', true),
  ('WK-SN-9', 'WK', 'wk.synonyms', 5, 'PERFUNCTORY most nearly means:', '["Thorough","Cursory","Enthusiastic","Secretive"]'::jsonb, 1, 'Perfunctory means done with minimum effort, as a routine duty; going through the motions. Recruits often guess ''secretive'' because of the per- prefix.', true),
  ('WK-SN-10', 'WK', 'wk.synonyms', 5, 'RECALCITRANT most nearly means:', '["Obedient","Defiant","Cautious","Calculating"]'::jsonb, 1, 'Recalcitrant means stubbornly resistant to authority or control. ''Calculating'' is a common wrong answer due to visual similarity. From Latin calcitrare, to kick.', true),
  ('AO-3D-1', 'AO', 'ao.3d-visualization', 3, 'A solid cube rests flat on a table. The top face is painted red. The cube is rotated 90° forward — tilting toward you, pivoting around its front bottom edge. After this rotation, which face is now on top?', '["The original top face (red)","The original front face","The original back face","The original bottom face"]'::jsonb, 1, 'Rotating 90° forward around the front bottom edge lifts the front face up to become the new top. The red original top now faces toward you (the new front).', true),
  ('AO-3D-3', 'AO', 'ao.3d-visualization', 4, 'A cube''s faces are colored: top = white, bottom = black, front = red, back = green, left = blue, right = yellow. The cube is rotated 90° to the right (around the vertical axis — the right side swings to the front). What color is now on top?', '["White","Black","Yellow","Blue"]'::jsonb, 0, 'Rotating around the vertical axis does not change the top or bottom faces — only the four side faces rotate. The top remains white.', true),
  ('AO-3D-4', 'AO', 'ao.3d-visualization', 3, 'Using the same colored cube (top = white, front = red, right = yellow, bottom = black, back = green, left = blue): after rotating 90° to the right around the vertical axis, what color is now facing you (front)?', '["Red","Green","Yellow","Blue"]'::jsonb, 2, 'Rotating the cube 90° to the right (vertical axis) brings the right face (yellow) to the front. Red rotates to the left, green to the right, and blue to the back.', true),
  ('AO-3D-5', 'AO', 'ao.3d-visualization', 5, 'A cube is sliced by a flat plane that passes through exactly three vertices of the cube, one vertex on each of three different faces that share no common edge. What shape is the cross-section?', '["Square","Rectangle","Equilateral triangle","Right triangle"]'::jsonb, 2, 'A plane through three mutually non-adjacent vertices of a cube cuts through three face diagonals of equal length, forming an equilateral triangle cross-section.', true),
  ('AO-PF-1', 'AO', 'ao.paper-folding-nets', 3, 'A flat net consists of 1 center square with 4 squares attached, one to each side (forming a plus/cross shape — 5 squares total). When folded, what 3D shape does it create?', '["A cube","A square pyramid","An open-top box (box without a lid)","A triangular prism"]'::jsonb, 2, 'Five squares form a base plus four walls but no top. You need 6 squares to close a cube. This net creates an open-top box.', true),
  ('AO-PF-3', 'AO', 'ao.paper-folding-nets', 3, 'A flat net consists of a square in the center with 4 equilateral triangles attached to each of the square''s edges. When folded, what shape does it form?', '["A cube","A rectangular prism","A square pyramid","A triangular prism"]'::jsonb, 2, 'The four triangles fold upward and their free vertices meet at a single point above the square base, forming a square pyramid.', true),
  ('AO-PF-4', 'AO', 'ao.paper-folding-nets', 4, 'A cube net: face A is in the center; face B is directly above A; face C is directly below A; face D is to the left of A; face E is to the right of A; face F is directly below C. When folded into a cube, which face is directly opposite face B?', '["Face A","Face C","Face F","Face D"]'::jsonb, 1, 'With face A as the base of the cube, B folds up to be the back wall and C folds up to be the front wall — making B and C opposite faces. D and E become the left and right sides (also opposite). F, attached to C’s far edge, folds over to become the top — making F opposite A. Therefore the face opposite B is C.', true),
  ('AO-PF-5', 'AO', 'ao.paper-folding-nets', 5, 'A square sheet of paper is folded in half by bringing the bottom edge up to meet the top edge (a horizontal fold). The resulting rectangle is then folded in half by bringing the right edge over to meet the left edge (a vertical fold). The paper is then fully unfolded. How many rectangular sections does the paper have?', '["2","4","6","8"]'::jsonb, 1, 'The first fold creates 2 sections; the second fold divides each of those in half. When unfolded, the paper has 2 × 2 = 4 rectangular sections separated by the two crease lines.', true),
  ('AO-SC-1', 'AO', 'ao.spatial-counting', 3, 'A structure is built by stacking cubes. The bottom layer is a 3×3 grid (9 cubes). The second layer is a 2×2 grid centered on the first (4 cubes). The third layer has 1 cube centered on the second. How many cubes are in the structure?', '["9","12","14","16"]'::jsonb, 2, 'Total = 9 + 4 + 1 = 14 cubes.', true),
  ('AO-SC-3', 'AO', 'ao.spatial-counting', 3, 'You see a staircase of cubes: 3 cubes on the bottom row, 2 cubes on the middle row, and 1 cube on the top. All rows are aligned to the left edge. How many cubes are in the structure?', '["5","6","7","9"]'::jsonb, 1, 'Total = 3 + 2 + 1 = 6 cubes.', true),
  ('AO-SC-4', 'AO', 'ao.spatial-counting', 4, 'A 2×3 single-layer base (6 cubes) sits on a table. A second layer of 2×2 cubes is stacked on top starting from one corner. How many cubes are in the complete structure?', '["8","9","10","12"]'::jsonb, 2, 'Bottom layer: 2 × 3 = 6. Second layer: 2 × 2 = 4. Total = 6 + 4 = 10 cubes.', true),
  ('AO-SC-5', 'AO', 'ao.spatial-counting', 5, 'A 4×4×4 large cube is built from unit cubes. How many unit cubes are completely hidden inside (touching no outer face)?', '["0","4","8","16"]'::jsonb, 2, 'The hidden interior is a (4−2)×(4−2)×(4−2) = 2×2×2 = 8 unit cube block. Every other unit cube touches at least one outer face.', true);
commit;
